INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 51 AND s.display_order = 1), '어제 전화한 사람은 오래전에 같은 학교를 다녔던 친구입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 51 AND s.display_order = 1), '옆에 사는 여자는 대학병원에서 근무하고 성격도 친절합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 51 AND s.display_order = 1), '길에서 나를 도와준 남자는 알고 보니 같은 동네 주민이어서 놀랐습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 51 AND s.display_order = 1), '무대에서 노래하는 소녀가 제 동생인데 어릴 때부터 꿈을 키워 온 결과입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 51 AND s.display_order = 1), '이 건물에서 일하는 사람들은 부지런하기로 유명해서 성과가 항상 좋습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 51 AND s.display_order = 1), '지난 파티에서 만난 사람이 우리 팀의 리더가 되었는데 능력이 뛰어나서 모두 만족합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 51 AND s.display_order = 2), '서점에서 산 책은 재미있지만 번역이 약간 어색합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 51 AND s.display_order = 2), '그녀가 직접 만든 케이크는 예쁘기도 했지만 맛도 정말 좋았습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 51 AND s.display_order = 2), '어제 본 영화는 줄거리가 복잡했는데 영상미가 뛰어나서 끝까지 집중할 수 있었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 51 AND s.display_order = 2), '공원 중앙에 있는 나무는 백 년이 넘었지만 관리를 잘해서 여전히 건강합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 51 AND s.display_order = 2), '우리가 사용하는 컴퓨터는 오래되었기 때문에 속도가 느려서 곧 교체해야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 51 AND s.display_order = 2), '테이블 위에 있는 가방은 제 것인데 아래에 있는 것은 동생이 두고 간 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 51 AND s.display_order = 3), '지난주에 본 영화는 기대보다 훨씬 좋아서 다시 보고 싶습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 51 AND s.display_order = 3), '그녀가 보낸 편지는 길었지만 진심이 느껴져서 감동적이었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 51 AND s.display_order = 3), '우리가 주문한 음식은 양이 많았는데 맛도 좋아서 모두 만족했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 51 AND s.display_order = 3), '행사에서 만난 사람은 유머가 있어서 이야기하는 내내 즐거운 시간을 보냈습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 51 AND s.display_order = 3), '그녀가 추천한 식당은 비쌌지만 음식이 맛있었기 때문에 돈이 아깝지 않았습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 51 AND s.display_order = 3), '도서관에서 빌린 책이 흥미로워서 밤늦게까지 읽다가 결국 하루 만에 다 끝냈습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 51 AND s.display_order = 4), '우리가 저녁을 먹은 식당은 비싸지만 분위기가 좋았습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 51 AND s.display_order = 4), '내가 태어난 도시는 작지만 자연환경이 아름다워서 자주 방문합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 51 AND s.display_order = 4), '그들이 사는 집은 넓을 뿐 아니라 교통도 편리해서 부러울 정도입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 51 AND s.display_order = 4), '우리가 처음 만난 카페는 예전에는 조용했는데 지금은 항상 붐비고 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 51 AND s.display_order = 4), '그녀가 일하는 회사는 유명하기 때문에 경쟁이 치열해서 입사하기 어렵습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 51 AND s.display_order = 4), '아이들이 주로 노는 공원은 넓고 안전해서 부모들이 안심하고 보낼 수 있습니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 52 AND s.display_order = 1), '3시간째 공부하고 있어서 머리가 아프기 시작합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 52 AND s.display_order = 1), '아침부터 비가 내리고 있는데 오후에는 그칠 것 같습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 52 AND s.display_order = 1), '한 시간째 기다리고 있지만 연락이 없어서 다른 방법을 찾아야 할 것 같습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 52 AND s.display_order = 1), '하루 종일 일하고 있어서 저녁에는 쉬면서 좋아하는 드라마를 보고 싶습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 52 AND s.display_order = 1), '30분째 전화 통화 중인데 문제가 해결되지 않아서 직접 방문해야 할 것 같습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 52 AND s.display_order = 1), '2시간째 요리하고 있지만 아직 반도 못 끝내서 손님 오기 전에 걱정됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 52 AND s.display_order = 2), '얼마나 오래 기다렸는지 모르지만 결국 좋은 결과가 나왔습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 52 AND s.display_order = 2), '여기서 얼마나 오래 일하셨는지 궁금해서 여쭤봐도 될까요?', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 52 AND s.display_order = 2), '얼마나 오래 공부했는지 몰랐는데 창밖을 보니 벌써 밤이 되어 있었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 52 AND s.display_order = 2), '아까부터 무엇을 하고 계셨는지 궁금했지만 방해가 될까 봐 묻지 못했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 52 AND s.display_order = 2), '몇 시간째 운전하셨는지 모르겠지만 피곤하시면 쉬었다 가시는 것이 좋겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 52 AND s.display_order = 2), '아침부터 운동하고 계셨다면 지금쯤 많이 피곤하실 테니 충분히 쉬시기 바랍니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 52 AND s.display_order = 3), '책 세 권을 다 읽었지만 내용을 완전히 이해하지는 못했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 52 AND s.display_order = 3), '아침부터 책을 읽고 있는데 내용이 어려워서 진도가 잘 나가지 않습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 52 AND s.display_order = 3), '보고서를 다 썼으므로 이제 검토만 하면 되는데 오늘 안에 끝낼 수 있을 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 52 AND s.display_order = 3), '아까부터 보고서를 쓰고 있지만 자료가 부족해서 마무리하기 어렵습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 52 AND s.display_order = 3), '벽을 다 칠한 후에 가구를 배치할 계획인데 이번 주말까지 끝낼 수 있을 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 52 AND s.display_order = 3), '오전부터 벽을 칠하고 있는데 혼자 하니까 생각보다 시간이 오래 걸리고 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 52 AND s.display_order = 4), '2020년부터 여기 살고 있는데 동네가 점점 좋아지고 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 52 AND s.display_order = 4), '3년간 영어를 공부하고 있지만 아직 유창하게 말하기 어렵습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 52 AND s.display_order = 4), '대학 졸업 후부터 같은 회사에서 일해 왔기 때문에 그 분야의 경험이 풍부합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 52 AND s.display_order = 4), '10년째 피아노를 치고 있는데 배울수록 더 어려워져서 끝이 없는 것 같습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 52 AND s.display_order = 4), '어렸을 때부터 수영을 해 왔기 때문에 물에 대한 두려움이 전혀 없습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 52 AND s.display_order = 4), '5시간째 운전하고 있으므로 안전을 위해 다음 휴게소에서 꼭 쉬어야 합니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 53 AND s.display_order = 1), '그녀가 어디 사는지 아는 사람이 있으면 알려 주세요', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 53 AND s.display_order = 1), '회의가 몇 시에 시작하는지 아직 모르기 때문에 확인하겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 53 AND s.display_order = 1), '그가 왜 갑자기 떠났는지 모르겠지만 나름대로 이유가 있었을 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 53 AND s.display_order = 1), '이것이 얼마인지 물어보고 싶었는데 직원이 바빠 보여서 기다리고 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 53 AND s.display_order = 1), '누가 이 프로젝트를 이끌었는지 궁금해서 찾아봤더니 경력이 풍부한 분이었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 53 AND s.display_order = 1), '그녀가 무엇을 원하는지 정확히 모르기 때문에 직접 만나서 물어볼 예정입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 53 AND s.display_order = 2), '그가 올지 궁금하지만 직접 물어보기는 어렵습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 53 AND s.display_order = 2), '이 답이 맞는지 확인해야 하므로 선생님께 여쭤보겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 53 AND s.display_order = 2), '내일 비가 올지 모르겠지만 혹시 모르니 우산을 가져가는 것이 좋겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 53 AND s.display_order = 2), '그녀가 제안에 동의할지 확실하지 않아서 다른 방법도 미리 준비해 두었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 53 AND s.display_order = 2), '가게가 아직 열었는지 확인한 후에 출발해야 헛걸음하지 않을 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 53 AND s.display_order = 2), '그들이 참석할지 알려주시면 인원에 맞춰서 자리를 미리 준비하겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 53 AND s.display_order = 3), '거기까지 어떻게 가는지 알려주시면 감사하겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 53 AND s.display_order = 3), '비밀번호가 뭔지 잊어버렸는데 다시 설정할 수 있을까요?', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 53 AND s.display_order = 3), '어디서 표를 사는지 아시면 저에게도 알려 주시기 바랍니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 53 AND s.display_order = 3), '가장 가까운 역이 어딘지 모르겠는데 지도를 확인해 봐야 할 것 같습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 53 AND s.display_order = 3), '이 가게가 언제 닫는지 알려주시면 그 전에 가서 필요한 것을 사겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 53 AND s.display_order = 3), '이 양식을 어떻게 작성하는지 모르겠으니 시간 되시면 도와주시겠어요?', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 53 AND s.display_order = 4), '몇 시에 시작하는지 모르겠으니 담당자에게 확인하겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 53 AND s.display_order = 4), '누가 담당자인지 확인 중이며 결과가 나오면 곧 알려드리겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 53 AND s.display_order = 4), '얼마나 걸릴지 예상할 수 없지만 최대한 빨리 마치도록 최선을 다하겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 53 AND s.display_order = 4), '그가 어디 갔는지 아무도 모르기 때문에 연락이 올 때까지 기다리는 중입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 53 AND s.display_order = 4), '결과가 어떻게 될지 지켜봐야 하므로 지금 단계에서는 판단하기 이릅니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 53 AND s.display_order = 4), '왜 지연되었는지 원인을 파악 중이며 확인되는 대로 바로 보고하겠습니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 54 AND s.display_order = 1), '돈이 충분하다면 세계여행을 하고 다양한 문화를 경험할 텐데', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 54 AND s.display_order = 1), '시간이 더 있다면 운동도 하면서 취미 생활도 즐길 수 있을 텐데', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 54 AND s.display_order = 1), '차가 있다면 대중교통 대신 직접 운전해서 출퇴근하면 편할 텐데 아쉽습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 54 AND s.display_order = 1), '날개가 있다면 비행기를 타지 않아도 어디든 갈 수 있을 텐데 상상만 해봅니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 54 AND s.display_order = 1), '그 나라에 살면 자연스럽게 언어를 배울 수 있을 텐데 현실적으로 어렵습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 54 AND s.display_order = 1), '가까이 살면 매일 만날 수 있지만 거리가 멀어서 자주 보기 힘듭니다', '기본'),
