  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 54 AND s.display_order = 3), '복권에 당첨되면 먼저 무엇을 하실 건지 궁금합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 54 AND s.display_order = 3), '대통령이 된다면 가장 먼저 어떤 정책을 바꾸실 건가요?', '기본'),
