  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 55 AND s.display_order = 1), '오늘이 어제보다 훨씬 더운데 습도는 낮아서 견딜 만합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 55 AND s.display_order = 1), '이 식당이 저 식당보다 훨씬 싸고 맛도 좋아서 자주 옵니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 55 AND s.display_order = 1), '그녀가 나보다 훨씬 빠르기 때문에 경주에서 이기기가 어렵습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 55 AND s.display_order = 1), '새 제품이 이전 것보다 훨씬 가볍기 때문에 휴대하기 편해서 인기가 많습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 55 AND s.display_order = 1), '이 문제가 예상보다 훨씬 어려워서 해결하는 데 시간이 오래 걸리고 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 55 AND s.display_order = 2), '연습할수록 실력이 늘기 때문에 꾸준한 노력이 중요합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 55 AND s.display_order = 2), '많이 읽을수록 더 많이 알게 되므로 독서 습관을 기르세요', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 55 AND s.display_order = 2), '빨리 시작할수록 빨리 끝나기 때문에 미루지 말고 바로 시작하는 것이 좋습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 55 AND s.display_order = 2), '높이 올라갈수록 공기가 차가워지므로 산에 갈 때는 따뜻한 옷을 준비하세요', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 55 AND s.display_order = 2), '오래 기다릴수록 더 힘들어지니까 차라리 지금 다른 방법을 찾는 것이 낫습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 55 AND s.display_order = 2), '열심히 할수록 결과가 좋아지는 것은 사실이지만 건강 관리도 소홀히 하면 안 됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 55 AND s.display_order = 3), '이것은 저것의 두 배 비싸지만 품질이 훨씬 좋습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 55 AND s.display_order = 3), '이 방은 저 방보다 세 배 크기 때문에 사무실로 사용합니다', '기본'),
