  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 55 AND s.display_order = 3), '이 가방은 저것보다 두 배 무겁기 때문에 오래 들고 다니면 어깨가 아픕니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 55 AND s.display_order = 3), '올해 매출이 작년의 두 배로 늘었는데 그에 비해 비용도 상당히 증가했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 55 AND s.display_order = 3), '이 도시 인구는 그 도시의 세 배이지만 면적은 비슷해서 인구 밀도가 매우 높습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 55 AND s.display_order = 4), '이것은 내가 본 최고의 영화이며 주변에 강력히 추천합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 55 AND s.display_order = 4), '지금까지 먹어본 중 가장 맛있어서 조리법을 꼭 알고 싶습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 55 AND s.display_order = 4), '이것보다 좋은 것은 없으므로 더 이상 찾아볼 필요 없이 바로 결정하세요', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 55 AND s.display_order = 4), '서비스가 점점 좋아지고 있어서 고객 만족도가 꾸준히 높아지는 추세입니다', '기본'),
