  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 56 AND s.display_order = 1), '날씨가 좋으니 아이들을 밖에서 놀게 해주면 건강에도 도움이 될 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 56 AND s.display_order = 2), '그가 서둘러 나가는 것을 봤지만 어디로 가는지는 모릅니다', '기본'),
