  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 56 AND s.display_order = 2), '문이 갑자기 닫히는 소리를 듣고 놀라서 뒤를 돌아봤더니 바람 때문이었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 56 AND s.display_order = 3), '전문가에게 고치게 했더니 이전보다 훨씬 잘 작동합니다', '기본'),
