  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 56 AND s.display_order = 3), '친구에게 도와달라고 했더니 혼자 할 때보다 훨씬 빨리 끝나서 고마웠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 56 AND s.display_order = 3), '의사에게 다시 확인하도록 요청했더니 별 문제가 없다고 해서 안심했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 56 AND s.display_order = 3), '동생에게 방을 청소하게 했지만 아직도 어수선해서 다시 시켜야 할 것 같습니다', '기본'),
