  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 57 AND s.display_order = 1), '팀워크를 중요하게 생각할 뿐 아니라 필요할 때는 리더십도 발휘할 수 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 57 AND s.display_order = 1), '새로운 것을 배우는 걸 좋아하기 때문에 어떤 환경에서든 빠르게 적응합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 57 AND s.display_order = 1), '이전 직장에서 3년 근무하면서 팀 매출을 두 배로 올린 경험이 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 57 AND s.display_order = 1), '이 분야에 열정이 있으며 장기적으로 전문가로 성장하고 싶습니다', '기본'),
