  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 57 AND s.display_order = 2), '금요일까지 마치겠지만 내용에 따라 추가 검토가 필요할 수도 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 57 AND s.display_order = 2), '현재 80% 완료되었으므로 일정을 맞춰서 이번 주 안에 마무리할 수 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 57 AND s.display_order = 2), '약간의 지연이 있지만 전체 일정에는 영향을 주지 않으니 걱정하지 않으셔도 됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 57 AND s.display_order = 2), '다음 주까지 결과를 보고하겠으며 진행 상황이 바뀌면 중간에도 공유하겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 57 AND s.display_order = 2), '목표를 달성했을 뿐 아니라 예상보다 빨리 완료해서 다음 단계를 준비하고 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 57 AND s.display_order = 3), '화면을 공유하겠으니 자료를 함께 보면서 논의합시다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 57 AND s.display_order = 3), '한 가지 추가하고 싶은 것이 있는데 잠깐 말씀드려도 될까요?', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 57 AND s.display_order = 3), '이 주제는 충분히 논의했으므로 결론을 정리하고 다음 안건으로 넘어가겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 57 AND s.display_order = 3), '이 제안에 대해 의견을 말씀해 주시면 최대한 반영하도록 하겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 57 AND s.display_order = 3), '지금까지 논의한 내용을 정리해 보면 크게 세 가지로 요약할 수 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 57 AND s.display_order = 3), '다음 회의는 월요일에 하겠으며 그때까지 각자 맡은 자료를 준비해 주세요', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 57 AND s.display_order = 4), '일정 변경 사항을 알려드리기 위해 이 글을 씁니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 57 AND s.display_order = 4), '첨부 파일을 확인하시고 수정할 부분이 있으면 알려 주세요', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 57 AND s.display_order = 4), '빠른 답변 부탁드리며 궁금한 점이 있으시면 언제든지 연락해 주세요', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 57 AND s.display_order = 4), '일정을 확인하셔서 참석 가능 여부를 회신해 주시면 자리를 미리 준비하겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 57 AND s.display_order = 4), '문의 사항이 있으시면 편하게 연락 주시기 바라며 신속히 답변드리겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 57 AND s.display_order = 4), '바쁘신 중에도 협조해 주셔서 감사드리며 앞으로도 잘 부탁드립니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 58 AND s.display_order = 1), '보고서에 따르면 경제가 성장했지만 소득 격차는 넓어졌습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 58 AND s.display_order = 1), '새로운 정책이 발표되었으며 다음 달부터 시행될 예정입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 58 AND s.display_order = 1), '전문가들에 의하면 상황이 개선되고 있지만 아직 안심하기에는 이른 단계입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 58 AND s.display_order = 1), '조사 결과가 오늘 공개되었는데 예상과 다른 부분이 있어서 논란이 일고 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 58 AND s.display_order = 1), '대변인이 공식 입장을 밝혔으며 추가 발표는 내일 오전에 있을 예정입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 58 AND s.display_order = 1), '새 법안이 통과되었다고 보도되었지만 시민 단체를 중심으로 반대 의견도 많습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 58 AND s.display_order = 2), '어젯밤에 화재가 발생했지만 소방관들이 빠르게 진화했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 58 AND s.display_order = 2), '교차로에서 사고가 발생했기 때문에 교통이 크게 혼잡해졌습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 58 AND s.display_order = 2), '경찰이 현장에 도착한 후 목격자들에게 진술을 요청하고 증거를 수집했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 58 AND s.display_order = 2), '다행히 부상자는 없었지만 건물 일부가 크게 파손되어서 수리가 필요합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 58 AND s.display_order = 2), '원인을 조사하고 있으며 결과가 나오면 다음 주에 공식 발표할 예정입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 58 AND s.display_order = 2), '도로가 두 시간 동안 통제되었기 때문에 많은 차량이 우회해야 하는 상황이었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 58 AND s.display_order = 3), '매출이 20% 증가했지만 비용도 늘어서 순이익은 소폭 감소했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 58 AND s.display_order = 3), '인구가 지난 10년간 두 배가 되었으므로 주택 수요가 크게 늘었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 58 AND s.display_order = 3), '실업률이 3%로 떨어졌지만 청년층의 실업 문제는 여전히 심각한 상황입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 58 AND s.display_order = 3), '방문객 수가 크게 늘었을 뿐 아니라 평균 체류 기간도 길어지는 추세입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 58 AND s.display_order = 3), '평균 기온이 2도 올랐기 때문에 농작물 생산량에 눈에 띄는 영향을 주고 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 58 AND s.display_order = 3), '전체의 약 60%가 찬성한 반면에 나머지는 강하게 반대해서 의견이 갈렸습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 58 AND s.display_order = 4), '이 문제에 대해 어떻게 생각하시는지 의견을 듣고 싶습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 58 AND s.display_order = 4), '제 생각에는 더 논의가 필요하며 섣불리 결정하면 안 됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 58 AND s.display_order = 4), '그 의견에는 동의하지만 구체적인 실행 방법에 대해서는 다르게 생각합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 58 AND s.display_order = 4), '다른 관점도 있을 수 있으므로 결정하기 전에 다양한 입장을 고려해야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 58 AND s.display_order = 4), '장단점을 모두 고려해야 하며 한쪽 면만 보면 올바른 판단을 내리기 어렵습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 58 AND s.display_order = 4), '저는 다르게 생각하는데 그 이유를 간략히 설명해 드리겠습니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 59 AND s.display_order = 1), '연기가 인상적이었고 각본도 훌륭해서 기대 이상이었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 59 AND s.display_order = 1), '줄거리가 예측 가능한 반면에 영상미가 뛰어나서 끝까지 볼 수 있었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 59 AND s.display_order = 1), '결말이 예상 밖이어서 영화가 끝난 후에도 한동안 여운이 남아 있었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 59 AND s.display_order = 1), '영상미가 아름다웠고 음악도 장면에 잘 어울려서 몰입감이 뛰어났습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 59 AND s.display_order = 1), '이 영화는 실화를 바탕으로 만들어졌기 때문에 보면서 더욱 감동적이었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 59 AND s.display_order = 1), '주인공이 역경을 극복하면서 성장하는 과정이 인상 깊어서 오래 기억에 남습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 59 AND s.display_order = 2), '저는 그 가수의 팬이며 콘서트에도 여러 번 갔습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 59 AND s.display_order = 2), '콘서트가 정말 좋았는데 관객 모두가 열광해서 분위기가 뜨거웠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 59 AND s.display_order = 2), '그 노래의 가사가 아름다울 뿐 아니라 멜로디도 귀에 남아서 자주 듣습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 59 AND s.display_order = 2), '무대 연출이 화려했는데 조명이 음악과 잘 어울려서 감동이 배가 되었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 59 AND s.display_order = 2), '그녀의 목소리는 독특하기 때문에 한번 들으면 쉽게 잊을 수 없습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 59 AND s.display_order = 2), '이 곡은 들을수록 기분이 좋아져서 출퇴근할 때마다 반복해서 듣고 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 59 AND s.display_order = 3), '이 그림은 18세기 작품인데 보존 상태가 매우 양호합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 59 AND s.display_order = 3), '전시회가 다음 달까지 계속되므로 시간 될 때 방문하세요', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 59 AND s.display_order = 3), '이 조각상은 매우 섬세하며 가까이서 보면 작가의 정성이 느껴져서 감탄하게 됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 59 AND s.display_order = 3), '박물관에 흥미로운 유물이 많기 때문에 하루로는 다 보기가 어렵습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 59 AND s.display_order = 3), '이 작품은 유명한 화가가 그렸는데 세계적으로 높이 평가되어 관람객이 많습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 59 AND s.display_order = 3), '사진 촬영은 금지되어 있지만 기념품점에서 도록을 사면 작품을 다시 볼 수 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 59 AND s.display_order = 4), '이 이야기는 우정에 관한 것이며 읽을수록 감동이 깊어집니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 59 AND s.display_order = 4), '작가는 자연을 아름답게 묘사할 뿐 아니라 인물도 생생하게 그려냅니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 59 AND s.display_order = 4), '이 소설은 여러 언어로 번역되었기 때문에 전 세계적으로 많은 독자를 확보했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 59 AND s.display_order = 4), '주인공은 용감한 소년인데 다양한 모험을 통해 점점 성장하는 과정이 매력적입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 59 AND s.display_order = 4), '이 책은 읽기 쉬울 뿐 아니라 내용도 유익해서 남녀노소 모두에게 추천합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 59 AND s.display_order = 4), '그 시인은 사랑에 대해 많이 썼는데 작품마다 깊은 감정이 담겨 있어 인기가 많습니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 60 AND s.display_order = 1), '대기 오염이 심해지고 있으므로 대책 마련이 시급합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 60 AND s.display_order = 1), '재활용을 더 많이 해야 할 뿐 아니라 소비 자체도 줄이는 노력이 필요합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 60 AND s.display_order = 1), '플라스틱 사용을 줄이지 않으면 환경 파괴가 심해져서 미래 세대에 큰 피해를 줍니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 60 AND s.display_order = 1), '지구 온난화는 심각한 문제이며 모든 나라가 함께 협력해야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 60 AND s.display_order = 1), '숲을 보호하는 것이 중요한데 이는 생태계 전체에 영향을 미치기 때문입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 60 AND s.display_order = 1), '깨끗한 에너지를 사용해야 하며 화석 연료에 대한 의존도를 낮추는 것이 급선무입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 60 AND s.display_order = 2), '교육은 모든 사람에게 중요하며 기회의 평등이 보장되어야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 60 AND s.display_order = 2), '모두가 동등한 기회를 가져야 하지만 현실은 아직 그렇지 못합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 60 AND s.display_order = 2), '빈곤 문제 해결이 시급할 뿐 아니라 재발을 막기 위한 장기적 대책도 필요합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 60 AND s.display_order = 2), '다양성을 존중해야 하며 서로 다른 의견도 경청하는 자세가 무엇보다 중요합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 60 AND s.display_order = 2), '봉사활동은 사회에 도움이 될 뿐 아니라 참여하는 사람에게도 보람을 줍니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 60 AND s.display_order = 2), '안전한 도시를 만들려면 시민과 정부가 힘을 합쳐서 함께 노력해야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 60 AND s.display_order = 3), '규칙적인 운동은 스트레스를 줄여주고 집중력도 높여줍니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 60 AND s.display_order = 3), '하루에 물을 충분히 마시는 것이 좋으며 건강에 큰 도움이 됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 60 AND s.display_order = 3), '충분한 수면이 건강에 필수적이지만 많은 사람들이 이 사실을 간과하고 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 60 AND s.display_order = 3), '균형 잡힌 식단이 중요한데 특히 채소와 과일을 충분히 섭취해야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 60 AND s.display_order = 3), '스트레스 관리가 건강의 핵심이므로 자기에게 맞는 해소법을 찾는 것이 좋습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 60 AND s.display_order = 3), '정기적으로 검진을 받으면 질병을 조기에 발견할 수 있어서 치료도 수월합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 60 AND s.display_order = 4), '기술이 우리 삶을 크게 바꿨으며 앞으로도 변화는 계속될 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 60 AND s.display_order = 4), '온라인 쇼핑이 편리해지고 있는 반면에 개인정보 보호가 더욱 중요해졌습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 60 AND s.display_order = 4), '인공지능이 많은 분야에서 쓰이고 있지만 윤리적인 문제도 함께 논의해야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 60 AND s.display_order = 4), '스마트폰 없이는 생활하기 어려운데 이것이 편리함인 동시에 의존의 문제이기도 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 60 AND s.display_order = 4), '기술 발전이 일자리를 변화시키고 있으므로 새로운 능력을 키우는 것이 필수입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 60 AND s.display_order = 4), '디지털 보안이 점점 중요해지고 있기 때문에 비밀번호 관리를 철저히 해야 합니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 61 AND s.display_order = 1), '그녀가 도착했을 때 우리는 이미 식사를 마치고 커피를 마시고 있었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 61 AND s.display_order = 1), '영화가 시작되기 전에 팝콘을 다 먹었다는 것을 나중에야 깨달았습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 61 AND s.display_order = 1), '비가 오기 전에 빨래를 걷어 놓았으므로 다행히 젖지 않았습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 61 AND s.display_order = 1), '선생님이 질문하기 전에 이미 답을 알고 있었는데 다른 학생들은 당황한 표정이었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 61 AND s.display_order = 1), '기차가 출발하기 전에 역에 도착했기 때문에 여유롭게 자리를 찾을 수 있었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 61 AND s.display_order = 1), '그가 전화하기 전에 이미 소식을 들어서 크게 놀라지는 않았습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 61 AND s.display_order = 2), '시험 종이 울렸을 때 아직 끝내지 못했기 때문에 결과가 걱정되었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 61 AND s.display_order = 2), '그가 물었을 때 아직 결정하지 못한 상태였으므로 대답을 미룰 수밖에 없었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 61 AND s.display_order = 2), '회의가 시작되었을 때 보고서를 준비하지 못한 채 참석해서 매우 난처했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 61 AND s.display_order = 2), '버스가 왔을 때 아직 아침을 먹지 못했고 준비도 되지 않았습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 61 AND s.display_order = 2), '마감일까지 프로젝트를 완료하지 못했으므로 사정을 설명하고 연장을 요청했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 61 AND s.display_order = 2), '그녀가 오기 전까지 청소를 하지 않았다는 사실이 나중에 작은 문제가 되었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 61 AND s.display_order = 3), '그 나라에 가기 전에 현지 문화를 미리 조사한 적이 있으셨나요?', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 61 AND s.display_order = 3), '그녀를 만나기 전에 그녀에 대해 들어본 적이 있었는지 궁금합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 61 AND s.display_order = 3), '그 영화를 보기 전에 원작 소설을 읽었는지 물어봐도 될까요?', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 61 AND s.display_order = 3), '시험 전에 충분히 공부했었는지 아니면 준비가 부족했는지 돌이켜 보면 어떤가요?', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 61 AND s.display_order = 3), '파티에 오기 전에 저녁을 먹었는지 기억이 안 나서 물어보는 건데 어떠셨나요?', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 61 AND s.display_order = 3), '면접 전에 그 회사에 대해 조사를 충분히 했었는지 지금 생각해 보면 아쉬운 점이 있나요?', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 61 AND s.display_order = 4), '숙제를 끝낸 후에 친구들과 놀러 나갔는데 그때서야 마음이 편해졌습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 61 AND s.display_order = 4), '저녁을 먹은 후에 산책을 하다가 우연히 옛 친구를 만나게 되었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 61 AND s.display_order = 4), '모든 손님이 떠난 후에 정리를 시작했더니 예상보다 시간이 오래 걸렸습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 61 AND s.display_order = 4), '계약서에 서명한 후에 마음이 바뀌었지만 이미 되돌릴 수 없는 상황이었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 61 AND s.display_order = 4), '비행기가 이륙한 후에야 여권을 두고 왔다는 것을 깨달아서 크게 당황했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 61 AND s.display_order = 4), '보고서를 제출한 후에 오류를 발견했으나 수정할 기회가 이미 지나 버렸습니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 62 AND s.display_order = 1), '내일 이 시간에 비행기를 타고 있을 것이므로 전화를 받기 어렵습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 62 AND s.display_order = 1), '오후 3시에 회의를 하고 있을 것이기 때문에 다른 일정은 잡지 마세요', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 62 AND s.display_order = 1), '내일 저녁에 친구들과 식사하고 있을 텐데 동생은 혼자 공부하고 있을 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 62 AND s.display_order = 1), '다음 주 이맘때 해변에서 쉬고 있을 거라는 생각만으로도 벌써 기분이 좋아집니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 62 AND s.display_order = 1), '내년 이 시간에 대학교에 다니고 있을 것이므로 지금부터 열심히 준비해야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 62 AND s.display_order = 1), '자정이 되면 모두 자고 있을 것이니 늦게 들어오실 때는 조용히 해주세요', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 62 AND s.display_order = 2), '오늘 밤에 차를 사용하실 건지 아니면 제가 빌려도 되는지 여쭤봅니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 62 AND s.display_order = 2), '내일 오후에 사무실에 계실 건지 확인하고 싶어서 미리 연락드립니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 62 AND s.display_order = 2), '주말에 컴퓨터를 사용하고 계실 건지 아니면 제가 써도 괜찮은지 알려 주세요', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 62 AND s.display_order = 2), '이번 주 금요일에 근무하실 건지 아니면 휴가를 내실 건지 일정이 궁금합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 62 AND s.display_order = 2), '내일 아침에 도서관에서 공부하실 건지 미리 알면 같이 가서 좋을 텐데요', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 62 AND s.display_order = 2), '다음 달에도 같은 프로젝트를 하고 계실 건지 아니면 새 업무가 배정될 건지요?', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 62 AND s.display_order = 3), '그때 비행 중일 것이므로 인터넷 연결이 불안정할 수 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 62 AND s.display_order = 3), '정오에 기차로 이동 중일 것이기 때문에 화상 회의에 참석하기 어렵습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 62 AND s.display_order = 3), '내일 이맘때 발표를 하고 있을 거라고 생각하면 벌써부터 긴장이 됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 62 AND s.display_order = 3), '다음 주에는 새 사무실에서 일하고 있을 텐데 환경이 어떨지 기대됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 62 AND s.display_order = 3), '12월에는 졸업 준비를 하고 있을 것이므로 그때는 다른 약속을 잡기 어렵습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 62 AND s.display_order = 3), '오후 5시에는 퇴근하고 있을 것이니 그 후에 만나면 서로 편할 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 62 AND s.display_order = 4), '저녁 식사에 참석하실 건지 미리 알려주시면 자리를 준비하겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 62 AND s.display_order = 4), '내일 회의에 오실 건지 확인하려는데 혹시 일정이 바뀌셨나요?', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 62 AND s.display_order = 4), '주말 행사에 함께하실 건지 아니면 다른 계획이 있으신지 여쭤봐도 될까요?', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 62 AND s.display_order = 4), '오후에 잠깐 시간을 내실 수 있으신지 논의할 사안이 있어서 여쭤보는 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 62 AND s.display_order = 4), '다음 주에 출장을 같이 가실 건지 확정이 되면 미리 알려주시기 바랍니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 62 AND s.display_order = 4), '이번 학기에 그 수업을 들으실 건지 아니면 다음 학기로 미루실 건지 궁금합니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 63 AND s.display_order = 1), '그는 피곤하다고 말했는데 표정을 보니 정말 지쳐 보였습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 63 AND s.display_order = 1), '그녀는 내일 오겠다고 했지만 날씨가 나쁘면 못 올 수도 있다고 했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 63 AND s.display_order = 1), '그들은 결과에 만족한다고 말했고 동시에 개선할 점도 있다고 인정했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 63 AND s.display_order = 1), '의사가 더 쉬어야 한다고 말했으므로 당분간 업무량을 줄이기로 결정했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 63 AND s.display_order = 1), '선생님이 시험이 어려울 거라고 말했는데 실제로 풀어 보니 정말 그랬습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 63 AND s.display_order = 1), '그는 새 직장을 구했다고 말하면서 기존 동료들이 그리울 거라고도 덧붙였습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 63 AND s.display_order = 2), '그녀가 어디 사는지 물었더니 개인적인 질문이라며 대답을 피했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 63 AND s.display_order = 2), '회의가 몇 시에 시작하는지 물었으나 아무도 정확한 시간을 모르고 있었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 63 AND s.display_order = 2), '왜 늦었는지 물었을 때 교통 체증 때문이었다고 설명하면서 사과했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 63 AND s.display_order = 2), '프로젝트가 언제 끝나는지 물었더니 예산 상황에 따라 달라질 수 있다고 답했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 63 AND s.display_order = 2), '누가 그 일을 담당하는지 물었지만 아직 담당자가 정해지지 않았다고 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 63 AND s.display_order = 2), '어떻게 문제를 해결했는지 물었더니 팀 전체가 협력한 결과라고 대답했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 63 AND s.display_order = 3), '의사가 담배를 끊으라고 했을 뿐 아니라 규칙적으로 운동하라고도 권했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 63 AND s.display_order = 3), '선생님이 조용히 하라고 했지만 학생들이 계속 떠들어서 다시 경고했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 63 AND s.display_order = 3), '그녀가 창문을 닫아 달라고 부탁한 이유는 밖에서 소음이 심했기 때문입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 63 AND s.display_order = 3), '경찰이 차를 세우라고 말했으므로 즉시 갓길에 정차할 수밖에 없었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 63 AND s.display_order = 3), '부모님이 늦게까지 밖에 있지 말라고 했는데도 자정이 넘어서야 들어왔습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 63 AND s.display_order = 3), '매니저가 보고서를 다시 작성하라고 했으므로 주말 동안 수정 작업을 해야 했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 63 AND s.display_order = 4), '그는 지난주에 아팠다고 말했는데 지금은 회복된 것 같아 다행입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 63 AND s.display_order = 4), '그녀는 이미 표를 샀다고 했고 나는 아직 예매하지 못한 상태였습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 63 AND s.display_order = 4), '그가 그 소식을 전날 들었다고 말했으므로 우리보다 먼저 알고 있었던 셈입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 63 AND s.display_order = 4), '그녀는 5년째 거기서 일하고 있다고 하면서 곧 이직할 계획이라고도 덧붙였습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 63 AND s.display_order = 4), '그들은 그곳에 가본 적이 없다고 말했기 때문에 제가 직접 안내하기로 했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 63 AND s.display_order = 4), '그는 다음 날 일찍 떠날 거라고 했으므로 전날 밤에 미리 작별 인사를 나눴습니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 64 AND s.display_order = 1), '더 열심히 준비했더라면 발표가 성공적이었을 텐데 지금 생각하면 아쉽습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 64 AND s.display_order = 1), '일찍 출발했더라면 비행기를 놓치지 않았을 것이고 일정도 차질이 없었을 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 64 AND s.display_order = 1), '지도를 미리 확인했더라면 길을 잃지 않았을 텐데 그때는 생각을 못 했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 64 AND s.display_order = 1), '우산을 가져왔더라면 젖지 않았을 것이고 감기에도 걸리지 않았을 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 64 AND s.display_order = 1), '그 소식을 미리 알았더라면 도와줬을 텐데 아무도 알려주지 않아서 안타깝습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 64 AND s.display_order = 1), '충분히 잤더라면 더 잘 집중했을 것이므로 결과가 달라졌을 수도 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 64 AND s.display_order = 2), '그가 도와주지 않았다면 실패했을 거라는 사실을 지금도 잊지 않고 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 64 AND s.display_order = 2), '안전벨트를 하지 않았다면 크게 다쳤을 것이므로 항상 착용하는 것이 중요합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 64 AND s.display_order = 2), '그 약을 먹지 않았다면 더 아팠을 거라고 의사가 나중에 설명해 주었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 64 AND s.display_order = 2), '친구가 돈을 빌려주지 않았다면 살 수 없었을 것이기에 진심으로 감사합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 64 AND s.display_order = 2), '경고를 받지 못했다면 위험했을 거라는 생각에 지금도 소름이 돋곤 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 64 AND s.display_order = 2), '인터넷이 없었다면 정보를 찾기 어려웠을 뿐 아니라 연락도 힘들었을 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 64 AND s.display_order = 3), '만약 그 자리에 있었다면 어떻게 했을지 솔직히 말해 주세요', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 64 AND s.display_order = 3), '그때 다른 선택을 했다면 지금 삶이 어떻게 달라졌을지 가끔 궁금합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 64 AND s.display_order = 3), '더 많은 시간이 있었다면 무엇을 했을지 한번 생각해 보신 적이 있나요?', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 64 AND s.display_order = 3), '그 제안을 받아들였다면 어떻게 됐을지 아무도 모르지만 후회가 남습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 64 AND s.display_order = 3), '그녀가 진실을 말했다면 상황이 어떻게 변했을지 당시에 모두가 궁금해했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 64 AND s.display_order = 3), '다른 나라에서 태어났다면 어떤 삶을 살았을지 가끔 상상해 보곤 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 64 AND s.display_order = 4), '당신 말을 들었어야 했는데 고집을 부린 것이 지금도 후회됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 64 AND s.display_order = 4), '그때 더 용기를 냈으면 좋았을 텐데 두려움 때문에 기회를 놓쳐 버렸습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 64 AND s.display_order = 4), '젊었을 때 더 많이 여행했으면 좋았을 텐데 바쁘다는 핑계로 미루기만 했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 64 AND s.display_order = 4), '그 기회를 놓치지 않았으면 좋았을 텐데 당시에는 중요성을 몰랐던 것이 아쉽습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 64 AND s.display_order = 4), '더 일찍 시작했으면 좋았을 텐데 미루다 보니 시간이 부족해져 버렸습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 64 AND s.display_order = 4), '그런 말을 하지 않았으면 좋았을 텐데 이미 내뱉은 말은 주워 담을 수 없습니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 65 AND s.display_order = 1), '다리가 성공적으로 수리되었으므로 내일부터 차량 통행이 재개됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 65 AND s.display_order = 1), '새 정책이 도입되었을 뿐 아니라 기존 규정도 대폭 개정되어 혼란이 있었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 65 AND s.display_order = 1), '모든 티켓이 이미 판매되었기 때문에 추가 공연을 검토하고 있다고 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 65 AND s.display_order = 1), '건물이 최근에 개조되었는데 이전보다 훨씬 현대적이고 편리해졌습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 65 AND s.display_order = 1), '결과가 웹사이트에 게시되었으므로 관심 있는 분들은 직접 확인하시기 바랍니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 65 AND s.display_order = 1), '용의자가 체포되었다는 소식이 전해지면서 동네 주민들이 안도하는 분위기입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 65 AND s.display_order = 2), '도로가 현재 공사 중이므로 우회 도로를 이용해 주시기 바랍니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 65 AND s.display_order = 2), '새 병원이 건설되고 있으며 기존 병원도 확장 공사가 함께 진행 중입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 65 AND s.display_order = 2), '그 문제가 조사되고 있으므로 결과가 나올 때까지 조금만 기다려 주시기 바랍니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 65 AND s.display_order = 2), '주문하신 음식이 준비되고 있으니 잠시만 기다려 주시면 바로 가져다 드리겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 65 AND s.display_order = 2), '시스템이 업데이트되고 있는 동안에는 일시적으로 서비스 이용이 제한될 수 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 65 AND s.display_order = 2), '새로운 규칙이 시행되고 있는데도 불구하고 아직 모르는 직원들이 꽤 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 65 AND s.display_order = 3), '이 문제는 즉시 해결되어야 하므로 담당 부서에 긴급 요청을 보냈습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 65 AND s.display_order = 3), '규칙은 모든 사람이 준수해야 하며 예외는 허용되지 않습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 65 AND s.display_order = 3), '신청서는 온라인으로 제출할 수 있을 뿐 아니라 우편으로도 접수가 가능합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 65 AND s.display_order = 3), '이 제품은 냉장 보관되어야 하므로 개봉 후에는 즉시 냉장고에 넣어 주세요', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 65 AND s.display_order = 3), '더 많은 연구가 수행되어야 정확한 결론을 내릴 수 있다고 전문가들이 말합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 65 AND s.display_order = 3), '이 서류는 내일까지 서명되어야 하며 그렇지 않으면 계약 자체가 무효가 됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 65 AND s.display_order = 4), '그녀는 뛰어난 요리 실력으로 유명하며 친절한 성격으로도 알려져 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 65 AND s.display_order = 4), '저는 고전 음악에 관심이 있는 반면에 동생은 현대 미술에 더 끌린다고 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 65 AND s.display_order = 4), '그는 결과에 만족한다고 말했지만 표정을 보면 아쉬움이 남아 있는 듯합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 65 AND s.display_order = 4), '우리는 그 뉴스에 놀랐을 뿐 아니라 앞으로 어떻게 될지 걱정이 되었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 65 AND s.display_order = 4), '이 지역은 아름다운 경치로 유명하기 때문에 해마다 관광객이 꾸준히 방문합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 65 AND s.display_order = 4), '그들은 우리의 도움에 감사하면서도 스스로 해결하지 못한 점을 아쉬워했습니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 66 AND s.display_order = 1), '차가 도난당한 그 남자는 경찰에 신고했지만 아직 범인이 잡히지 않았습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 66 AND s.display_order = 1), '딸이 의사인 그 여성은 제 이웃인데 건강 관련 조언을 자주 해주셔서 감사합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 66 AND s.display_order = 1), '지붕이 손상된 그 집은 수리가 시급하지만 예산이 부족해서 고민 중입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 66 AND s.display_order = 1), '작품이 전시된 그 화가는 이전에는 무명이었는데 이번 전시를 계기로 유명해졌습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 66 AND s.display_order = 1), '아이디어가 채택된 그 직원은 승진했을 뿐 아니라 특별 보너스도 받았습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 66 AND s.display_order = 1), '아들이 유학 중인 그 부부를 만났는데 아들이 보고 싶다며 눈물을 글썽였습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 66 AND s.display_order = 2), '제가 이야기한 그 분은 친절했고 전문 지식도 풍부했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 66 AND s.display_order = 2), '제가 함께 일한 그 팀은 훌륭했는데 다시 협력할 기회가 있으면 좋겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 66 AND s.display_order = 2), '내가 앉았던 그 의자는 불편했기 때문에 회의 내내 집중하기가 어려웠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 66 AND s.display_order = 2), '그녀가 살고 있는 그 도시는 경치가 아름답지만 생활비가 높다고 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 66 AND s.display_order = 2), '제가 다닌 그 학교가 최근에 문을 닫았다는 소식을 듣고 매우 안타까웠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 66 AND s.display_order = 2), '우리가 의존하는 시스템이 고장 났으므로 대체 방안을 긴급히 마련해야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 66 AND s.display_order = 3), '그가 늦은 이유를 아무도 모르기 때문에 여러 추측만 오가고 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 66 AND s.display_order = 3), '제가 태어난 마을은 매우 작았지만 그곳에서의 추억은 지금도 소중합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 66 AND s.display_order = 3), '우리가 처음 만난 날을 기억하시는지 그때 무슨 이야기를 했는지 궁금합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 66 AND s.display_order = 3), '그녀가 갑자기 떠난 이유를 나중에야 알게 되었는데 사정을 듣고 이해했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 66 AND s.display_order = 3), '그가 일하는 방식이 독특한 반면에 결과물은 항상 기대 이상으로 뛰어납니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 66 AND s.display_order = 3), '우리가 결혼한 장소를 다시 방문했더니 많이 변해서 처음에는 알아보지 못했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 66 AND s.display_order = 4), '먼저 도착하는 사람이 자리를 고를 수 있으므로 가능하면 일찍 오세요', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 66 AND s.display_order = 4), '무엇을 결정하든 저는 지지하겠으니 부담 갖지 말고 편하게 선택하세요', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 66 AND s.display_order = 4), '어디를 가든 항상 카메라를 가져가는 덕분에 좋은 사진이 많이 모였습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 66 AND s.display_order = 4), '무엇이든 필요한 것이 있으면 말해 주시기만 하면 최선을 다해 도와드리겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 66 AND s.display_order = 4), '누구든 규칙을 어기면 벌금을 내야 하며 예외 없이 동일하게 적용됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 66 AND s.display_order = 4), '어느 것을 선택하든 후회하지 않을 것이니 마음이 이끄는 대로 결정하세요', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 67 AND s.display_order = 1), '이 책을 추천하는 이유는 실용적이면서도 읽기 쉽기 때문입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 67 AND s.display_order = 1), '직접 경험해 보시면 왜 인기가 많은지 바로 이해하실 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 67 AND s.display_order = 1), '이것이 최선의 선택이라고 확신하므로 다른 대안을 찾느라 시간을 낭비하지 마세요', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 67 AND s.display_order = 1), '이 기회를 놓치지 않으셨으면 하는데 이런 조건은 다시 오기 어렵기 때문입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 67 AND s.display_order = 1), '장기적으로 보면 이것이 더 경제적일 뿐 아니라 유지 관리도 훨씬 편리합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 67 AND s.display_order = 1), '체험판부터 사용해 보시면 차이를 느끼실 것이므로 우선 시도해 보시기를 권합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 67 AND s.display_order = 2), '말씀은 이해하지만 다른 방법도 있으므로 여러 가능성을 열어 두고 논의합시다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 67 AND s.display_order = 2), '중간 가격은 어떨지 제안드리는데 양측 모두 수용 가능한 선이라고 봅니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 67 AND s.display_order = 2), '그 점은 인정하지만 한 가지 조건이 있으므로 그 부분에 대해서도 합의가 필요합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 67 AND s.display_order = 2), '좋은 지적이지만 이 부분도 함께 고려해 주셔야 공정한 결정을 내릴 수 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 67 AND s.display_order = 2), '서로 양보한다면 합의에 이를 수 있으므로 각자 한 발씩 물러서면 어떨까요?', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 67 AND s.display_order = 2), '귀하의 의견을 존중하는 반면에 저희 입장도 이해해 주시면 감사하겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 67 AND s.display_order = 3), '가격을 낮추시면 대량 주문하겠으며 장기 계약도 체결할 수 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 67 AND s.display_order = 3), '배송을 앞당겨 주시면 계약하겠지만 그렇지 않으면 다른 업체를 알아봐야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 67 AND s.display_order = 3), '보증 기간을 연장해 주시면 동의하겠으므로 이 조건을 꼭 검토해 주시기 바랍니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 67 AND s.display_order = 3), '추가 교육을 제공해 주시면 수락하겠는데 직원 역량 강화가 우선이기 때문입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 67 AND s.display_order = 3), '일정을 조정해 주시면 참여할 수 있으니 가능한 날짜를 몇 가지 알려 주세요', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 67 AND s.display_order = 3), '서면 확인을 해주시면 진행하겠으며 구두 합의만으로는 불충분하다고 판단됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 67 AND s.display_order = 4), '따라서 이 방법이 가장 효율적이므로 즉시 실행에 옮기는 것을 제안합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 67 AND s.display_order = 4), '결론적으로 변화가 필요하다고 생각하므로 구체적인 실행 계획을 세웁시다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 67 AND s.display_order = 4), '요약하자면 세 가지 핵심 사항이 있으며 각각에 대해 합의가 이루어져야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 67 AND s.display_order = 4), '이상의 이유로 이 제안을 권장하며 동시에 예상되는 위험 요소도 충분히 인지하고 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 67 AND s.display_order = 4), '모든 점을 고려했을 때 이것이 최선이라는 결론에 도달했으므로 승인을 요청합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 67 AND s.display_order = 4), '전반적으로 긍정적인 결과를 기대하지만 몇 가지 변수에 대한 대비도 필요합니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 68 AND s.display_order = 1), '안도되면서도 약간 실망스러운 것은 기대했던 것과 결과가 달랐기 때문입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 68 AND s.display_order = 1), '기쁘면서도 걱정이 되는 이유는 새로운 책임이 함께 따르기 때문입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 68 AND s.display_order = 1), '설레면서도 긴장되는 마음 때문에 밤새 잠을 이루기가 어려웠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 68 AND s.display_order = 1), '자랑스러우면서도 조금 슬픈 것은 아이가 독립한다는 뜻이기 때문입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 68 AND s.display_order = 1), '감사하면서도 미안한 마음이 드는 것은 너무 많은 도움을 받았기 때문입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 68 AND s.display_order = 1), '놀라우면서도 당연한 결과라고 느끼는 것은 그만큼 노력한 보람이기 때문입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 68 AND s.display_order = 2), '그런 상황에서 얼마나 힘드셨을지 이해하며 도울 일이 있으면 말씀하세요', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 68 AND s.display_order = 2), '정말 어려운 시간을 보내고 계신 것 같은데 혼자 감당하지 않으셔도 됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 68 AND s.display_order = 2), '그런 경험을 하셨다니 안타깝고 제가 도울 수 있는 일이 있다면 말씀해 주세요', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 68 AND s.display_order = 2), '그 기분이 어떤지 공감하는데 저도 비슷한 상황을 겪은 적이 있기 때문입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 68 AND s.display_order = 2), '같은 상황이라면 저도 그렇게 느꼈을 것이므로 너무 자책하지 않으셨으면 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 68 AND s.display_order = 2), '당신이 겪고 있는 일이 쉽지 않다는 걸 알지만 반드시 해결될 거라고 믿습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 68 AND s.display_order = 3), '포기하지 마세요, 지금까지의 노력이 분명 좋은 결과로 이어질 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 68 AND s.display_order = 3), '당신은 충분히 잘하고 있으므로 스스로를 너무 몰아세우지 마세요', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 68 AND s.display_order = 3), '이 어려움도 결국 지나갈 것이며 나중에 돌아보면 성장의 기회였다고 느낄 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 68 AND s.display_order = 3), '당신의 노력은 반드시 결실을 맺을 것이므로 조급해하지 말고 꾸준히 나아가세요', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 68 AND s.display_order = 3), '실패는 성공의 일부라는 것을 기억하시고 이번 경험을 소중한 교훈으로 삼으세요', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 68 AND s.display_order = 3), '당신을 믿고 있으며 어떤 어려움이 오더라도 해낼 수 있다고 확신합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 68 AND s.display_order = 4), '그때 가지 않은 것이 후회되는데 그런 기회는 다시 오지 않을 것 같습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 68 AND s.display_order = 4), '그런 말을 하지 말았어야 했는데 감정을 통제하지 못한 것이 부끄럽습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 68 AND s.display_order = 4), '더 신중하게 결정했어야 했다는 것을 나중에야 깨달았지만 이미 늦어 버렸습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 68 AND s.display_order = 4), '그녀에게 솔직하게 말할 걸 그랬는데 용기가 없어서 기회를 놓쳤습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 68 AND s.display_order = 4), '젊었을 때 더 많이 저축할 걸 그랬다고 후회하지만 지금이라도 시작하려 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 68 AND s.display_order = 4), '그 제안을 거절한 것을 후회하는데 당시에는 상황을 제대로 판단하지 못했습니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 69 AND s.display_order = 1), '그녀는 키가 큰 여성인데 첫인상이 매우 따뜻하고 친근했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 69 AND s.display_order = 1), '그는 안경을 쓴 친절한 남성이었으며 누구에게나 먼저 인사를 건네곤 했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 69 AND s.display_order = 1), '그녀는 항상 웃고 있는 사교적인 사람인 반면에 혼자만의 시간도 소중히 여깁니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 69 AND s.display_order = 1), '그는 조용하지만 매우 사려 깊은 사람이어서 그의 조언은 항상 신뢰할 수 있었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 69 AND s.display_order = 1), '운동선수 같은 체격의 남성이었는데 알고 보니 실제로 선수 출신이라 납득이 됐습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 69 AND s.display_order = 1), '그녀는 유머가 뛰어난 활발한 사람이라서 함께하면 시간이 빨리 지나갑니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 69 AND s.display_order = 2), '그 방은 작지만 아늑했으며 창밖 풍경이 마음을 편안하게 해주었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 69 AND s.display_order = 2), '거리는 가게들로 활기가 넘쳤을 뿐 아니라 거리 공연도 곳곳에서 펼쳐졌습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 69 AND s.display_order = 2), '그 공원은 오래된 나무들로 둘러싸여 있었는데 가을이 되면 단풍이 아름답습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 69 AND s.display_order = 2), '카페는 은은한 조명에 편안한 분위기여서 오래 앉아서 책을 읽기에 좋았습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 69 AND s.display_order = 2), '해변은 고운 모래와 맑은 물로 유명하지만 숙박 시설은 아직 부족한 편입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 69 AND s.display_order = 2), '도서관은 조용하고 넓었을 뿐 아니라 최신 자료도 잘 갖추어져 있어 자주 갔습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 69 AND s.display_order = 3), '먼저 재료를 모두 준비해야 하며 빠진 것이 없는지 목록을 확인하세요', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 69 AND s.display_order = 3), '양식을 작성하여 제출해야 하는데 누락된 항목이 있으면 반려될 수 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 69 AND s.display_order = 3), '승인을 받을 때까지 기다려야 하며 보통 영업일 기준으로 3일이 소요됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 69 AND s.display_order = 3), '마지막으로 결과를 확인하고 저장해야 하는데 이 단계를 빠뜨리면 데이터가 사라집니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 69 AND s.display_order = 3), '이 단계를 완료한 후에 다음으로 넘어가야 하며 순서를 바꾸면 오류가 생길 수 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 69 AND s.display_order = 3), '시작하기 전에 모든 도구를 점검해야 하므로 충분한 여유 시간을 확보해 두세요', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 69 AND s.display_order = 4), '그날은 꿈만 같았는데 돌이켜 보면 정말 그런 일이 있었는지 믿기지 않습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 69 AND s.display_order = 4), '그녀는 천사처럼 노래하지만 평소에는 매우 조용한 사람입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 69 AND s.display_order = 4), '시간이 화살처럼 빠르게 지나간다는 것을 나이가 들수록 더 절실히 느낍니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 69 AND s.display_order = 4), '그의 마음은 돌처럼 단단했으므로 어떤 말로도 그의 결심을 바꿀 수 없었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 69 AND s.display_order = 4), '아이들은 원숭이처럼 나무에 올랐는데 어른들은 위험하지 않을까 걱정했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 69 AND s.display_order = 4), '그 소식은 벼락처럼 갑작스러웠기 때문에 아무도 어떻게 반응할지 몰랐습니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 70 AND s.display_order = 1), '폭우 때문에 행사가 취소되었고 주변 도로도 통제되었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 70 AND s.display_order = 1), '교통사고로 인해 도로가 통제되었으므로 우회 경로를 이용해야 했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 70 AND s.display_order = 1), '예산 부족으로 프로젝트가 중단되었는데 이는 사전 기획이 부실했기 때문입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 70 AND s.display_order = 1), '꾸준히 노력한 덕분에 좋은 성과를 거두었으며 이를 바탕으로 새 목표를 세우고 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 70 AND s.display_order = 1), '수요 증가로 인해 가격이 올랐지만 공급이 안정되면 다시 내려갈 것으로 보입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 70 AND s.display_order = 1), '기술 발전 덕분에 생산성이 향상되었을 뿐 아니라 근무 환경도 크게 개선되었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 70 AND s.display_order = 2), '계획대로 진행되면 성공할 것이지만 예상 밖의 변수에도 대비해야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 70 AND s.display_order = 2), '예산이 승인되면 시작하겠으며 그렇지 않으면 규모를 축소해야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 70 AND s.display_order = 2), '날씨가 좋은 한 야외에서 진행하겠지만 만약을 위해 실내 장소도 준비해 두었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 70 AND s.display_order = 2), '만일의 경우에 대비해 계획을 세웠으므로 어떤 상황이 생겨도 대응할 수 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 70 AND s.display_order = 2), '그가 동의하지 않는 한 진행할 수 없으므로 먼저 그를 설득하는 것이 급선무입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 70 AND s.display_order = 2), '비용이 합리적이라면 참여하겠지만 예산을 초과하는 경우에는 재검토가 필요합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 70 AND s.display_order = 3), '비싸긴 했지만 그만한 가치가 있었으므로 결과적으로 잘한 선택이었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 70 AND s.display_order = 3), '어려움에도 불구하고 프로젝트를 완료했으며 팀워크가 더욱 강해졌습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 70 AND s.display_order = 3), '경험이 부족했음에도 열정으로 극복했다는 점에서 높이 평가받을 만합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 70 AND s.display_order = 3), '비가 왔음에도 불구하고 경기는 계속되었으며 선수들은 끝까지 최선을 다했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 70 AND s.display_order = 3), '반대 의견이 많았지만 찬성 측의 논리가 더 설득력이 있어서 결국 통과되었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 70 AND s.display_order = 3), '피곤했음에도 끝까지 완주했으며 그 순간의 성취감은 무엇과도 바꿀 수 없었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 70 AND s.display_order = 4), '게다가 서비스도 훌륭했으므로 다음에 다시 방문하고 싶습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 70 AND s.display_order = 4), '더욱이 가격도 합리적이었을 뿐 아니라 품질도 기대 이상으로 우수했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 70 AND s.display_order = 4), '뿐만 아니라 교통도 편리했기 때문에 어디를 가든 이동 시간이 짧았습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 70 AND s.display_order = 4), '무료 주차장도 있었으므로 차를 가져가더라도 비용 걱정이 없었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 70 AND s.display_order = 4), '특히 직원들의 친절함이 인상적이었는데 그런 태도가 고객 만족에 큰 영향을 줍니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 70 AND s.display_order = 4), '무엇보다 안전이 최우선이었으므로 모든 절차를 안전 기준에 따라 철저히 관리했습니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 71 AND s.display_order = 1), '그때까지 프로젝트를 마쳤을 것이므로 새 업무를 맡을 준비가 될 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 71 AND s.display_order = 1), '내년이면 졸업했을 것이니 취업 준비를 시작할 수 있을 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 71 AND s.display_order = 1), '도착할 때쯤이면 저녁을 다 만들었을 것이니 바로 식사하실 수 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 71 AND s.display_order = 1), '자정까지 보고서를 완료했을 것이므로 아침 회의에 제출할 수 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 71 AND s.display_order = 1), '회의 전에 자료를 준비했을 것이니 발표에 문제가 없을 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 71 AND s.display_order = 2), '정오까지 도착하지 못했을 것이므로 오후 일정을 조정해야 할 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 71 AND s.display_order = 2), '마감까지 끝내지 못할 것이기에 기한 연장을 요청해야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 71 AND s.display_order = 2), '그때까지 결정을 내리지 못했을 것이니 추가 논의가 필요할 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 71 AND s.display_order = 2), '출발 전에 짐을 다 싸지 못할 것이므로 택배로 보내야 하겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 71 AND s.display_order = 2), '월말까지 예산을 집행하지 못했을 것이므로 이월 절차를 준비합시다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 71 AND s.display_order = 3), '금요일까지 보고서를 완료하셨을지 여쭤봐도 되겠습니까?', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 71 AND s.display_order = 3), '돌아올 때까지 식사를 마쳤을지 아니면 기다려야 할까요?', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 71 AND s.display_order = 3), '여름까지 수리가 끝났을지 아직 확신할 수 없는 상황입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 71 AND s.display_order = 3), '내년이면 이전을 마쳤을 것인지 일정을 확인해 주시겠습니까?', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 71 AND s.display_order = 3), '회의 전까지 제안서를 검토하셨을지 미리 확인하고 싶습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 71 AND s.display_order = 4), '내년이면 여기 산 지 10년이 되므로 기념행사를 계획하고 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 71 AND s.display_order = 4), '다음 달이면 이 회사에서 일한 지 5년이 되니 승진을 기대합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 71 AND s.display_order = 4), '올해 말이면 영어를 배운 지 3년이 되므로 실력이 많이 늘었을 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 71 AND s.display_order = 4), '6월이면 함께한 지 20년이 되니 그 여정을 되돌아보게 됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 71 AND s.display_order = 4), '금요일이면 출장 간 지 2주가 되므로 곧 업무를 마무리할 것입니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 72 AND s.display_order = 1), '의학을 전공했더라면 지금 의사로서 환자를 돌보고 있을 텐데 아쉽습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 72 AND s.display_order = 1), '그 직장을 그만두지 않았다면 지금쯤 부장으로 승진했을 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 72 AND s.display_order = 1), '어릴 때 악기를 배웠다면 지금 무대에서 연주하고 있었을 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 72 AND s.display_order = 1), '투자 기회를 놓치지 않았더라면 경제적으로 훨씬 안정적이었을 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 72 AND s.display_order = 1), '외국에서 자랐다면 이중 언어를 유창하게 구사할 수 있었을 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 72 AND s.display_order = 2), '그는 모든 것을 아는 것처럼 행동하지만 실제로는 경험이 부족합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 72 AND s.display_order = 2), '그녀는 나를 못 본 것처럼 지나갔는데 일부러 그런 것 같았습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 72 AND s.display_order = 2), '그는 걱정이 없는 것처럼 보이지만 속으로는 고민이 많습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 72 AND s.display_order = 2), '마치 꿈을 꾸는 것 같아서 현실인지 확인하는 데 시간이 걸렸습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 72 AND s.display_order = 2), '그녀는 가본 적이 있는 것처럼 말했지만 실제로는 처음이었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 72 AND s.display_order = 3), '이미 늦었으므로 지금이라도 서둘러 출발해야 할 때입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 72 AND s.display_order = 3), '오해가 커지기 전에 진작 사과했어야 했는데 기회를 놓쳤습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 72 AND s.display_order = 3), '과거에 연연하지 말고 새로운 시작을 준비할 때라고 생각합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 72 AND s.display_order = 3), '상황이 이렇게 된 이상 진지하게 대안을 모색할 때가 되었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 72 AND s.display_order = 3), '더 이상 미루지 말고 지금 당장 결정을 내려야 할 때입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 72 AND s.display_order = 4), '건강을 위해서라도 여기서 담배를 피우지 않았으면 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 72 AND s.display_order = 4), '결론이 났으므로 그 문제에 대해 더 논의하지 않았으면 좋겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 72 AND s.display_order = 4), '초대를 받았지만 솔직히 차라리 집에서 쉬었으면 좋겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 72 AND s.display_order = 4), '팀원 의견을 듣지 않고 혼자 결정하지 않았으면 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 72 AND s.display_order = 4), '중요한 사안이니만큼 대리인 대신 본인이 직접 와 주었으면 합니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 73 AND s.display_order = 1), '퇴근길에 걷다가 오랫동안 연락이 끊겼던 옛 친구를 우연히 만났습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 73 AND s.display_order = 1), '음악을 들으면서 공부하면 오히려 집중력이 높아진다고 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 73 AND s.display_order = 1), '비 오는 풍경을 바라보며 창가에 앉아 따뜻한 차를 마셨습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 73 AND s.display_order = 1), '호텔에 도착하자마자 체크인을 하고 짐을 풀기 시작했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 73 AND s.display_order = 1), '서둘러 계단을 내려오다가 발을 헛디뎌 넘어질 뻔했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 73 AND s.display_order = 2), '하루 종일 일에 시달려 지쳤으므로 집에 오자마자 잠이 들었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 73 AND s.display_order = 2), '예상 밖의 결과에 놀라서 한동안 말을 잃고 멍하니 서 있었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 73 AND s.display_order = 2), '동료들의 격려 덕분에 힘을 얻어 더 열심히 노력하게 되었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 73 AND s.display_order = 2), '수년간 방치되어 낡아버린 건물은 점검 후 철거가 결정되었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 73 AND s.display_order = 2), '근거 없는 비판에 상처를 받았으므로 당분간 침묵을 지키기로 했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 73 AND s.display_order = 3), '갑작스러운 상황에 뭐라고 해야 할지 몰라 침묵할 수밖에 없었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 73 AND s.display_order = 3), '결과를 확신하지 못하여 충분한 정보가 모일 때까지 결정을 미루었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 73 AND s.display_order = 3), '초대를 받지 못했기 때문에 참석하는 것이 적절하지 않다고 봤습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 73 AND s.display_order = 3), '상황을 제대로 이해하지 못했으므로 담당자에게 직접 질문을 했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 73 AND s.display_order = 3), '정확한 답을 모른 채 추측하느니 차라리 그 문제를 건너뛰었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 73 AND s.display_order = 4), '날씨가 허락한다면 이번 주말에 가족과 함께 교외로 소풍을 갈 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 73 AND s.display_order = 4), '모든 요소를 종합적으로 고려하면 현재로서는 이것이 최선의 선택입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 73 AND s.display_order = 4), '시간이 허락한다면 근처 박물관도 방문하여 전시를 관람할 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 73 AND s.display_order = 4), '다른 조건이 동일하다면 내구성 면에서 이 제품이 더 낫습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 73 AND s.display_order = 4), '솔직히 말하자면 자원과 일정을 감안할 때 그 계획은 현실적이지 않습니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 74 AND s.display_order = 1), '다름 아닌 그가 실수로 꽃병을 깨뜨렸다는 사실이 나중에 밝혀졌습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 74 AND s.display_order = 1), '그녀에게서 가장 존경하는 것은 어떤 상황에서도 흔들리지 않는 용기입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 74 AND s.display_order = 1), '그녀를 처음 만난 곳이 바로 그 도시였다는 점에서 특별한 의미가 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 74 AND s.display_order = 1), '문제를 해결한 것은 개인의 능력이 아니라 팀워크의 힘이었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 74 AND s.display_order = 1), '상황의 심각성을 깨달은 것은 바로 그 순간이었다고 회상합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 74 AND s.display_order = 2), '바쁜 와중에도 시간을 내 주신 도움에 진심으로 감사드립니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 74 AND s.display_order = 2), '결과가 좋지 않았지만 정말 최선을 다했다고 자신 있게 말합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 74 AND s.display_order = 2), '경험이 적지만 그녀는 확실히 노래에 뛰어난 재능을 가지고 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 74 AND s.display_order = 2), '예상 밖의 소식을 듣고 정말로 깜짝 놀라지 않을 수 없었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 74 AND s.display_order = 2), '안전이 무엇보다 중요하므로 작업 중에는 반드시 조심하시기 바랍니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 74 AND s.display_order = 3), '여러 나라를 여행했지만 그렇게 아름다운 경치는 본 적이 없습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 74 AND s.display_order = 3), '다양한 식당을 다녀봤지만 이렇게 맛있는 음식은 처음이었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 74 AND s.display_order = 3), '어떤 이유가 있더라도 그런 무례한 행동은 결코 용납할 수 없습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 74 AND s.display_order = 3), '아무리 힘든 상황이 닥치더라도 절대 포기하지 않을 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 74 AND s.display_order = 3), '수많은 강연을 들어왔지만 그토록 감동적인 연설은 처음이었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 74 AND s.display_order = 4), '지금 가장 필요한 것은 일상에서 벗어나 재충전할 수 있는 휴가입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 74 AND s.display_order = 4), '그녀가 진정으로 원하는 것은 판단 없이 있는 그대로 이해받는 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 74 AND s.display_order = 4), '나를 가장 놀라게 한 것은 어려운 상황에서도 흔들리지 않은 그의 정직함입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 74 AND s.display_order = 4), '성공에서 중요한 것은 화려한 결과가 아니라 꾸준한 과정입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 74 AND s.display_order = 4), '우리가 해야 할 것은 기존 전략을 재검토하고 새 계획을 세우는 것입니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 75 AND s.display_order = 1), '3분기 매출 분석 결과를 바탕으로 향후 전략을 설명드리겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 75 AND s.display_order = 1), '이 그래프에서 보시다시피 전년 대비 뚜렷한 성장세를 보이고 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 75 AND s.display_order = 1), '지금까지의 내용을 정리한 후 세부 계획을 보여드리겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 75 AND s.display_order = 1), '요약하자면 오늘 논의한 핵심 사항이 향후 전략의 기반이 될 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 75 AND s.display_order = 1), '발표 내용에 대해 질문이 있으시면 마지막에 시간을 드리겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 75 AND s.display_order = 2), '대량 주문을 전제로 할인을 제안하오니 검토해 주십시오', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 75 AND s.display_order = 2), '장기적 파트너십을 위해 상호 이익이 되는 합의에 도달하고 싶습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 75 AND s.display_order = 2), '시장 상황을 고려하면 그 조건은 저희로서는 수용하기 어렵습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 75 AND s.display_order = 2), '양측의 입장 차이를 좁히기 위해 대안을 한 가지 제시하겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 75 AND s.display_order = 2), '핵심 조건에서 서로 양보하면 양측 모두 만족하는 합의를 찾을 수 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 75 AND s.display_order = 3), '배송이 기한을 넘겼기에 공식적으로 불만을 접수하고자 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 75 AND s.display_order = 3), '수령한 제품이 주문 당시의 설명 및 사양과 상당히 다릅니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 75 AND s.display_order = 3), '동일한 문제가 반복되고 있으므로 즉각적인 시정 조치를 요청합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 75 AND s.display_order = 3), '제품에 하자가 있으므로 관련 규정에 따라 전액 환불을 요구합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 75 AND s.display_order = 3), '이번 서비스의 품질은 계약서에 명시된 기대 수준에 미치지 못합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 75 AND s.display_order = 4), '정책 변경 사항에 대한 우려를 공식적으로 표명하고자 글을 드립니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 75 AND s.display_order = 4), '사안의 긴급성을 고려하여 귀하의 조속한 회신을 부탁드립니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 75 AND s.display_order = 4), '논의 사항을 정리한 첨부 문서를 검토하신 후 의견을 주시기 바랍니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 75 AND s.display_order = 4), '본 건과 관련하여 추가 설명이 필요하시면 언제든지 연락 주십시오', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 75 AND s.display_order = 4), '바쁘신 가운데 본 요청에 협조해 주신다면 대단히 감사하겠습니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 76 AND s.display_order = 1), '대규모 표본을 대상으로 한 연구 결과 유의미한 상관관계가 밝혀졌습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 76 AND s.display_order = 1), '실험 결과가 가설을 뒷받침하므로 후속 연구의 근거로 활용될 수 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 76 AND s.display_order = 1), '통제 집단과 실험 집단을 비교한 결과 통계적으로 유의미한 차이가 나타났습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 76 AND s.display_order = 1), '전국 규모의 조사에서 응답자의 70%가 해당 정책에 동의한 것으로 나타났습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 76 AND s.display_order = 1), '이번 연구 결과는 오랫동안 정설로 받아들여진 기존 이론에 의문을 제기합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 76 AND s.display_order = 2), '최근 보고서에 의하면 경제 정책 변화로 실업률이 감소한 것으로 나타났습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 76 AND s.display_order = 2), '해당 분야 전문가들에 따르면 이 성장 추세는 향후에도 지속될 전망입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 76 AND s.display_order = 2), '이전 연구에서 이미 지적한 바와 같이 표본 크기의 한계를 고려해야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 76 AND s.display_order = 2), '공식 통계를 인용하면 주요 산업 부문에서 경제가 회복 중인 것으로 나타납니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 76 AND s.display_order = 2), '국제기구의 권고에 따르면 예방이 공중 보건의 핵심 전략이라고 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 76 AND s.display_order = 3), '이 현상은 표면적 원인 외에 더 깊은 구조적 문제를 시사할 가능성이 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 76 AND s.display_order = 3), '현재 데이터만으로는 인과관계보다 상관관계를 시사하는 데 그칩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 76 AND s.display_order = 3), '연구 한계를 감안하면 외부 요인이 결과에 영향을 미쳤을 것으로 추정됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 76 AND s.display_order = 3), '반복적으로 나타나는 이 패턴은 일시적 현상이 아니라 체계적 문제일 수 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 76 AND s.display_order = 3), '현재 자료만으로는 추가 조사 없이 확정적 결론을 내리기가 어렵습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 76 AND s.display_order = 4), '이 현상은 발생 원인에 따라 크게 세 가지 범주로 분류될 수 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 76 AND s.display_order = 4), '지속 가능성은 미래 세대의 필요를 해치지 않으면서 현재 수요를 충족하는 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 76 AND s.display_order = 4), '이 용어는 넓은 의미에서 서로 관련된 두 가지 개념을 포함합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 76 AND s.display_order = 4), '기능적 특징에 따라 해당 체계는 두 가지 유형으로 구분됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 76 AND s.display_order = 4), '이 개념은 학문적 배경에 따라 학자마다 상이하게 해석되어 왔습니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 77 AND s.display_order = 1), '행복의 정의는 사람마다 다르므로 하나의 기준으로 측정하기 어렵습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 77 AND s.display_order = 1), '진정한 자유를 누리려면 그에 상응하는 책임을 받아들여야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 77 AND s.display_order = 1), '지식을 갖추었다 해도 그것이 반드시 지혜로 이어지지는 않는 법입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 77 AND s.display_order = 1), '삶의 의미는 주어지는 것이 아니라 각자가 만들어 가는 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 77 AND s.display_order = 1), '고통스러운 과정이라 할지라도 그것 없이는 진정한 성장을 기대하기 어렵습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 77 AND s.display_order = 2), '정직이야말로 모든 인간관계의 기초이며 신뢰를 쌓는 출발점입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 77 AND s.display_order = 2), '교육은 개인의 성장뿐 아니라 사회 전체의 발전을 이끄는 열쇠입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 77 AND s.display_order = 2), '서로 다른 관점과 배경을 가진 사람들의 다양성을 존중하는 것이 중요합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 77 AND s.display_order = 2), '어떤 분야에서든 성공을 위해 인내는 반드시 갖추어야 할 덕목입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 77 AND s.display_order = 2), '공정함은 어떤 상황에서도 타협할 수 없는 핵심 가치입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 77 AND s.display_order = 3), '결과가 좋다 해도 부당한 수단을 정당화할 수 있는지 깊이 생각해 봐야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 77 AND s.display_order = 3), '개인의 자유와 공공의 안전이 충돌할 때 우선순위를 정하기가 쉽지 않습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 77 AND s.display_order = 3), '오늘의 행동이 미래 세대에 미칠 장기적 영향을 진지하게 고려해야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 77 AND s.display_order = 3), '기술이 빠르게 발전하는 만큼 윤리적 한계도 함께 논의되어야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 77 AND s.display_order = 3), '부당한 상황에서 침묵하는 것이 동조하는 것과 다름없는지 성찰해야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 77 AND s.display_order = 4), '기술 혁신이 가속화됨에 따라 장기적으로 이 산업은 완전히 변모할 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 77 AND s.display_order = 4), '환경 문제가 심화되고 있으므로 재생 에너지가 주류가 될 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 77 AND s.display_order = 4), '현재의 발전 속도를 고려하면 10년 안에 상당한 변화가 예상됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 77 AND s.display_order = 4), '이 추세가 시정되지 않고 계속된다면 심각한 결과가 초래될 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 77 AND s.display_order = 4), '단기적 어려움이 있을지라도 궁극적으로 기술 발전이 해결해 줄 것입니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 78 AND s.display_order = 1), '우산도 없이 나왔는데 비가 쏟아져서 온몸이 흠뻑 젖고 말았습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 78 AND s.display_order = 1), '그는 어려운 상황에서도 항상 긍정적인 면을 찾으려고 노력합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 78 AND s.display_order = 1), '충분히 준비했기에 어려울 줄 알았던 시험이 식은 죽 먹기였습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 78 AND s.display_order = 1), '비밀을 지켜달라고 했는데도 그녀가 결국 모든 것을 누설했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 78 AND s.display_order = 1), '지금은 힘들더라도 포기하지 말고 끝까지 버텨야 좋은 결과가 옵니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 78 AND s.display_order = 2), '시간은 돈과 같으므로 한번 지나가면 되돌릴 수 없다는 점을 명심해야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 78 AND s.display_order = 2), '인생은 예측할 수 없는 여행이므로 유연하게 대처하는 자세가 중요합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 78 AND s.display_order = 2), '지식은 어둠 속의 빛과 같아서 무지로 인한 두려움을 없애 줍니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 78 AND s.display_order = 2), '그의 발언은 양날의 검이어서 긍정과 부정의 효과를 동시에 가져왔습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 78 AND s.display_order = 2), '교육은 성공의 초석이므로 어떤 상황에서도 배움을 소홀히 해서는 안 됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 78 AND s.display_order = 3), '오랜 투병 끝에 그분은 지난달 가족이 지켜보는 가운데 편히 떠나셨습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 78 AND s.display_order = 3), '구조조정 이후 그는 새로운 기회를 찾기 위해 적극적으로 구직 중입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 78 AND s.display_order = 3), '경영 효율화를 위해 회사가 여러 부서에 걸쳐 인력을 조정하고 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 78 AND s.display_order = 3), '예상치 못한 사정으로 그녀는 현재 경제적으로 어려운 상황에 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 78 AND s.display_order = 3), '개선을 시도했지만 그 제품은 소비자들의 기대에 미치지 못했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 78 AND s.display_order = 4), '세차를 하자마자 비가 내리다니 정말 좋은 타이밍이군요', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 78 AND s.display_order = 4), '마감이 코앞인데 새 업무까지 추가되다니 딱 필요했던 상황이네요', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 78 AND s.display_order = 4), '중요한 면접 날 차가 고장 나다니 운이 좋다고밖에 할 수 없군요', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 78 AND s.display_order = 4), '예약한 식당에서 한참을 기다리는 건 정말 즐거운 경험이었어요', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 78 AND s.display_order = 4), '야외 행사를 시작하려는 순간 비가 오다니 완벽한 타이밍이네요', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 79 AND s.display_order = 1), '정부에 따르면 새 정책이 내일부터 전국적으로 시행될 것으로 보도되었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 79 AND s.display_order = 1), '소식통에 따르면 양측 간 합의가 임박했으나 세부 조건은 조율 중입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 79 AND s.display_order = 1), '공식 발표에 앞서 세부 사항은 아직 확인되지 않은 상태입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 79 AND s.display_order = 1), '현장 목격자들이 사건 당시의 상황을 상세히 설명하며 증언했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 79 AND s.display_order = 1), '당국이 사건의 원인과 경위에 대한 본격적인 조사에 착수한 것으로 알려졌습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 79 AND s.display_order = 2), '그 영상이 올라온 지 하루 만에 수백만 조회를 기록하며 화제가 되었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 79 AND s.display_order = 2), '이 해시태그가 전 세계적으로 유행하면서 다양한 의견이 쏟아지고 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 79 AND s.display_order = 2), '게시물에 수천 개의 댓글이 달리면서 찬반 의견이 활발히 오가고 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 79 AND s.display_order = 2), '온라인에서 이 주제에 대해 치열한 논쟁이 벌어지며 관심이 집중됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 79 AND s.display_order = 2), '유명 인사가 계정을 개설하자마자 수만 명의 팔로워가 몰렸습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 79 AND s.display_order = 3), '기간 한정 특가이므로 재고가 소진되기 전에 지금 바로 주문하세요', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 79 AND s.display_order = 3), '이 가격에 이 품질을 만날 수 있는 기회를 절대 놓치지 마세요', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 79 AND s.display_order = 3), '품질 테스트를 통과하여 고객 만족도 1위를 달성한 제품입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 79 AND s.display_order = 3), '지금 주문하시면 추가 비용 없이 전국 어디든 무료 배송해 드립니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 79 AND s.display_order = 3), '전 세계 수백만 고객이 신뢰하는 브랜드를 직접 경험해 보세요', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 79 AND s.display_order = 4), '전반적 만족도를 고려하여 5점 만점에 4점을 주는 것이 적절합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 79 AND s.display_order = 4), '처음에는 기대하지 않았지만 결과적으로 모든 면에서 기대를 넘었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 79 AND s.display_order = 4), '가격에 비해 훌륭한 품질과 서비스를 동시에 제공받았습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 79 AND s.display_order = 4), '배송이 다소 느린 점을 제외하면 품질과 성능 면에서 강력히 추천합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 79 AND s.display_order = 4), '직접 사용해 본 경험에 비추어 다른 분들에게도 충분히 추천할 만합니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 80 AND s.display_order = 1), '양 당사자는 본 계약서에 명시된 조건과 의무에 상호 동의합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 80 AND s.display_order = 1), '본 계약은 양 당사자가 서명한 날로부터 법적 효력을 발생합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 80 AND s.display_order = 1), '일방이 계약 조건을 위반할 경우 본 계약은 즉시 해지될 수 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 80 AND s.display_order = 1), '본 계약 관련 모든 분쟁은 지정된 중재 기관을 통해 해결됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 80 AND s.display_order = 1), '계약 기간은 1년이며 별도 통보가 없는 한 자동 갱신됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 80 AND s.display_order = 2), '모든 직원은 입사 시 서약한 행동 강령을 근무 기간 동안 준수해야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 80 AND s.display_order = 2), '관리자의 사전 허가 없이 보안 구역에 출입하는 것은 엄격히 금지됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 80 AND s.display_order = 2), '수집된 개인 정보는 관련 법률과 내부 규정에 따라 철저히 보호됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 80 AND s.display_order = 2), '규정을 위반한 자에게는 절차에 따라 징계 조치가 취해질 수 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 80 AND s.display_order = 2), '본 정책은 직급이나 직무에 관계없이 모든 부서에 동일하게 적용됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 80 AND s.display_order = 3), '법률에 의거하여 모든 시민은 혐의에 대해 공정한 재판을 받을 권리가 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 80 AND s.display_order = 3), '법규에 따라 고용주는 직원에게 안전한 근무 환경을 제공할 의무가 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 80 AND s.display_order = 3), '소비자 보호법에 의거하여 구매자는 30일 이내 환불을 요청할 권리가 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 80 AND s.display_order = 3), '세법에 따라 납세자는 기한 내에 신고 및 납부를 완료할 의무가 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 80 AND s.display_order = 3), '헌법이 보장하는 바에 따라 모든 사람은 사생활 보호를 받을 권리가 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 80 AND s.display_order = 4), '본 서비스는 아래에 명시된 이용 약관에 따라 제공됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 80 AND s.display_order = 4), '천재지변이나 불가항력으로 인한 손해에 대해서는 책임지지 않습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 80 AND s.display_order = 4), '운영상 필요한 경우 사전 통보 없이 약관이 변경될 수 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 80 AND s.display_order = 4), '본 조항 일부가 무효로 판정되더라도 나머지 조항의 효력에는 영향이 없습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 80 AND s.display_order = 4), '이용 조건에 동의하지 않을 경우 본 서비스를 이용하실 수 없습니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 81 AND s.display_order = 1), '앉자마자 전화가 울렸고 급한 회의라 점심도 못 먹고 나가야 했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 81 AND s.display_order = 1), '그런 감동적인 연설은 들어본 적이 없었기에 모두가 숙연해졌습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 81 AND s.display_order = 1), '그가 떠나고 나서야 비로소 그의 진심을 알았기에 후회가 밀려왔습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 81 AND s.display_order = 1), '어떤 상황에서도 원칙을 포기해서는 안 되며 끝까지 지켜야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 81 AND s.display_order = 1), '문을 열자마자 경보가 울렸고 모든 직원이 즉시 대피하기 시작했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 81 AND s.display_order = 2), '언덕 위에 오래된 성이 서 있는데 수백 년의 역사를 간직하고 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 81 AND s.display_order = 2), '기회가 왔다가 순식간에 사라졌으므로 항상 준비해 두어야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 81 AND s.display_order = 2), '무대 위에 유명한 가수가 올라서자 관객들이 일제히 환호성을 질렀습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 81 AND s.display_order = 2), '문 앞에 소포가 놓여 있었는데 발신인이 적혀 있지 않아 의아했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 81 AND s.display_order = 2), '벽면을 따라 수천 권의 책이 빼곡히 꽂혀 있어서 장관을 이루었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 81 AND s.display_order = 3), '그가 찬성했고 저도 같은 의견인바 만장일치로 결정이 이루어졌습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 81 AND s.display_order = 3), '그녀도 그 소식을 접했으며 즉시 대응 방안을 마련하기 시작했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 81 AND s.display_order = 3), '그도 동의하지 않았거니와 다른 위원들 역시 반대 의견을 표명했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 81 AND s.display_order = 3), '저도 수영을 못하는 형편인바 수상 안전 교육이 반드시 필요합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 81 AND s.display_order = 3), '우리 팀도 그 결과에 만족하며 후속 프로젝트를 추진할 계획입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 81 AND s.display_order = 4), '미리 알았더라면 일찍 왔을 것이고 이런 혼란은 없었을 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 81 AND s.display_order = 4), '시간이 있었더라면 도왔을 텐데 일정이 겹쳐서 불가능했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 81 AND s.display_order = 4), '비가 내렸더라면 경기가 취소되었을 테니 오히려 다행이었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 81 AND s.display_order = 4), '필요하시면 언제든 연락해 주십시오, 신속히 지원해 드리겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 81 AND s.display_order = 4), '그녀가 동의했더라면 바로 진행했을 것이나 반대로 보류되었습니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 82 AND s.display_order = 1), '몇 달째 이 프로젝트를 진행해 오고 있으나 아직 해결할 과제가 남아 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 82 AND s.display_order = 1), '3년째 이 회사에서 일하고 있으며 그동안 많은 변화를 겪었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 82 AND s.display_order = 1), '오랫동안 이 문제를 연구해 왔는데 최근에야 비로소 실마리를 찾았습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 82 AND s.display_order = 1), '몇 주째 새 직원을 채용하려 하지만 적합한 후보를 찾기가 어렵습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 82 AND s.display_order = 1), '어릴 때부터 피아노를 쳐 왔기에 이제는 전문 연주자 수준에 이르렀습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 82 AND s.display_order = 2), '뛰어왔기 때문에 숨이 가쁜데 중요한 발표가 있어서 쉴 수도 없습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 82 AND s.display_order = 2), '밤새 공부해서 눈이 충혈되었으나 시험 결과가 좋아 보람을 느낍니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 82 AND s.display_order = 2), '비 속에 오래 서 있어서 옷이 다 젖었고 감기 기운까지 느껴집니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 82 AND s.display_order = 2), '하루 종일 걸어서 발이 아프지만 목적지에 거의 도착한 상태입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 82 AND s.display_order = 2), '장시간 회의를 진행해 와서 모두 지쳤으니 잠시 쉬었다가 합시다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 82 AND s.display_order = 3), '1시간 넘게 기다리고 있는데도 아무런 안내가 없어서 불만스럽습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 82 AND s.display_order = 3), '이 문제를 반복해서 설명해 왔건만 여전히 개선되지 않고 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 82 AND s.display_order = 3), '아침부터 계속 전화하고 있는데 받지 않아서 직접 방문해야겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 82 AND s.display_order = 3), '오랫동안 승진을 기다려 왔으나 기회가 오지 않아 전직을 고려합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 82 AND s.display_order = 3), '몇 시간째 줄을 서서 기다리고 있으니 접수 시스템 개선이 시급합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 82 AND s.display_order = 4), '물가가 꾸준히 오르고 있어서 서민 가계에 상당한 부담이 되고 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 82 AND s.display_order = 4), '기술이 급속히 발전하고 있으므로 지속적인 학습이 필수적인 시대입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 82 AND s.display_order = 4), '환경 문제가 점점 심각해지고 있는바 국제적 공조가 절실히 요구됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 82 AND s.display_order = 4), '출생률이 계속 감소하고 있어서 장기적으로 노동력 부족이 우려됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 82 AND s.display_order = 4), '재생 에너지 사용이 꾸준히 증가하고 있으며 이는 탄소 감축에 기여합니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 83 AND s.display_order = 1), '비가 오지 않았더라면 땅이 젖지 않았을 테고 행사도 진행되었을 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 83 AND s.display_order = 1), '열심히 공부했더라면 지금 의사일 텐데 그때의 선택이 아쉽습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 83 AND s.display_order = 1), '그때 투자했더라면 지금 부자일 테니 기회를 놓친 셈입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 83 AND s.display_order = 1), '어제 충분히 잤더라면 지금 피곤하지 않을 텐데 체력 관리가 필요합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 83 AND s.display_order = 1), '그 직장을 그만두지 않았더라면 지금쯤 임원이었을 테니 후회가 됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 83 AND s.display_order = 2), '투자하면 수익이 나고 그러면 사업을 확장할 수 있어서 성장이 가속됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 83 AND s.display_order = 2), '교육이 향상되면 실업이 줄고 경제가 성장하여 삶의 질이 높아집니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 83 AND s.display_order = 2), '일찍 출발하면 교통 체증을 피하고 제시간에 도착하여 여유를 가집니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 83 AND s.display_order = 2), '꾸준히 연습하면 실력이 늘고 자신감이 생겨서 좋은 성과로 이어집니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 83 AND s.display_order = 2), '철저히 계획을 세우면 효율이 오르고 시간과 비용이 모두 절약됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 83 AND s.display_order = 3), '당신의 도움이 아니었다면 실패했을 것이고 이 자리에 없었을 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 83 AND s.display_order = 3), '장학금이 아니었다면 졸업하지 못했을 것이니 정말 감사할 따름입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 83 AND s.display_order = 3), '그의 경고가 아니었다면 사고를 당했을 것이므로 큰 은혜를 입었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 83 AND s.display_order = 3), '의료팀의 신속한 대응이 아니었다면 생존이 어려웠을 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 83 AND s.display_order = 3), '그녀의 격려가 아니었다면 포기했을 텐데 덕분에 끝까지 해냈습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 83 AND s.display_order = 4), '무슨 일이 있더라도 포기하지 않겠다는 각오로 임하겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 83 AND s.display_order = 4), '그렇다 하더라도 우리는 계속해야 하며 멈출 수 없는 상황입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 83 AND s.display_order = 4), '어찌 되었든 최선을 다하겠으니 결과는 하늘에 맡기겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 83 AND s.display_order = 4), '만일의 경우에 대비하여 비상 계획을 수립해 두는 것이 현명합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 83 AND s.display_order = 4), '결과가 어떻든 간에 함께하겠다고 약속했으니 끝까지 지키겠습니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 84 AND s.display_order = 1), '교육이 사회 이동성의 핵심이라 주장하는바 다수의 연구가 이를 뒷받침합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 84 AND s.display_order = 1), '기후 변화가 최대 위협이라는 주장이 제기되고 있으며 대응이 시급합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 84 AND s.display_order = 1), '기술이 삶의 질을 향상시킨다고 주장하되 부작용도 고려해야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 84 AND s.display_order = 1), '세계화가 불평등을 심화시킨다는 주장이 있으나 반론도 만만치 않습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 84 AND s.display_order = 1), '다양성이 혁신을 촉진한다고 주장하며 이는 실증적 근거에 기반합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 84 AND s.display_order = 2), '반면에 비용이 너무 높다는 주장도 있어서 신중한 검토가 필요합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 84 AND s.display_order = 2), '장기적 효과는 불확실하므로 낙관적 전망만으로는 충분하지 않습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 84 AND s.display_order = 2), '반대로 이 정책이 역효과를 낳을 수 있다는 점도 간과할 수 없습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 84 AND s.display_order = 2), '다른 관점에서 보면 이점도 있거니와 절충안을 모색하는 것이 바람직합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 84 AND s.display_order = 2), '비판론자들은 증거가 불충분하다고 반박하며 추가 연구를 요구합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 84 AND s.display_order = 3), '실증적 증거가 이 가설을 뒷받침하므로 이론적 타당성이 확보됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 84 AND s.display_order = 3), '최근 연구에 기반하여 이 결론에 도달했으며 재현성도 확인되었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 84 AND s.display_order = 3), '통계 자료가 이 주장을 강력히 지지하는바 반박의 여지가 적습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 84 AND s.display_order = 3), '다수의 사례 연구가 이 이론을 확인해 주었고 일관된 결과를 보입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 84 AND s.display_order = 3), '실험 결과가 초기 가설과 일치하며 추가 실험에서도 동일한 경향입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 84 AND s.display_order = 4), '위 논의에 비추어 볼 때 제도적 변화가 불가피하다는 결론에 이릅니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 84 AND s.display_order = 4), '종합하면 이 접근법이 가장 효과적이며 즉각적인 도입을 권고합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 84 AND s.display_order = 4), '모든 요소를 고려할 때 결론은 명확하고 더 이상의 논의는 불필요합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 84 AND s.display_order = 4), '요약하자면 핵심 요점이 두 가지인바 이를 중심으로 정리하겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 84 AND s.display_order = 4), '궁극적으로 균형 잡힌 접근이 필요하며 양측의 합의가 전제되어야 합니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 85 AND s.display_order = 1), '유감이지만 이번에는 어렵겠으며 다른 기회에 함께하길 바랍니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 85 AND s.display_order = 1), '감사하지만 이번에는 사양하겠으니 차후에 다시 논의합시다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 85 AND s.display_order = 1), '마음은 감사하나 일정이 허락하지 않아서 대안을 제안드립니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 85 AND s.display_order = 1), '좋은 제안이지만 현재로서는 어렵기에 상황이 나아지면 재검토합시다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 85 AND s.display_order = 1), '면밀히 검토해 보았으나 진행이 어려울 듯하니 양해 부탁드립니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 85 AND s.display_order = 2), '실례지만 동의하기 어려우며 그 이유를 말씀드려도 되겠습니까', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 85 AND s.display_order = 2), '존중하지만 다른 견해를 가지고 있으니 잠시 설명할 기회를 주십시오', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 85 AND s.display_order = 2), '말씀은 이해하나 다른 관점도 있으므로 함께 검토해 보면 좋겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 85 AND s.display_order = 2), '일리가 있으나 전적으로 동의하기는 어려운바 보완이 필요해 보입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 85 AND s.display_order = 2), '그 의견도 타당하나 저는 다르게 보며 근거를 말씀드리겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 85 AND s.display_order = 3), '이 부분에 개선의 여지가 있을 수 있으니 재검토를 제안드립니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 85 AND s.display_order = 3), '약간의 수정이 결과를 향상시킬 수 있으므로 함께 논의해 봅시다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 85 AND s.display_order = 3), '다른 접근 방식을 고려해 볼 만하며 비교 분석이 도움이 될 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 85 AND s.display_order = 3), '이 전략이 기대에 완전히 부합하지는 않으므로 조정이 필요해 보입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 85 AND s.display_order = 3), '추가적인 검토가 도움이 되겠으니 전문가 의견을 구해 봅시다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 85 AND s.display_order = 4), '대안적 접근을 제안해도 될까요, 부담이 되시면 말씀해 주십시오', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 85 AND s.display_order = 4), '혹시 이런 방법은 어떨까 싶은데 더 나은 의견이 있으시면 환영합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 85 AND s.display_order = 4), '제 생각이 틀릴 수 있지만 한 가지 제안하니 참고만 해 주십시오', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 85 AND s.display_order = 4), '조심스럽게 의견을 드리자면 일정 조정이 효율적일 듯합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 85 AND s.display_order = 4), '작은 제안이지만 절차를 간소화하면 시간과 비용을 아낄 수 있습니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 86 AND s.display_order = 1), '옛날에 한 왕이 살았는데 그의 왕국에는 아무도 모르는 비밀이 숨겨져 있었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 86 AND s.display_order = 1), '그가 몰랐던 것은 모든 것이 곧 변하리라는 것이며 운명은 이미 정해져 있었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 86 AND s.display_order = 1), '어둠이 내리자 이상한 소리가 들렸고 불안감이 서서히 퍼져 나가기 시작했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 86 AND s.display_order = 1), '그날이 인생을 바꾸게 될 줄은 꿈에도 몰랐기에 평소처럼 하루를 시작했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 86 AND s.display_order = 1), '이야기는 한 작은 마을에서 시작되는데 그곳은 아무도 주목하지 않는 곳이었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 86 AND s.display_order = 2), '갓 구운 빵의 향기가 방 안을 가득 채웠고 따뜻한 온기가 감돌았습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 86 AND s.display_order = 2), '차가운 바람이 뺨을 스치는 가운데 먼 산에서 종소리가 울려 퍼졌습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 86 AND s.display_order = 2), '부드러운 선율이 고요한 밤을 채우자 모든 근심이 사라지는 듯했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 86 AND s.display_order = 2), '석양이 하늘을 붉게 물들이며 호수 위로 긴 그림자를 드리웠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 86 AND s.display_order = 2), '소금기 섞인 바닷바람이 얼굴에 닿았고 파도 소리가 귓가에 맴돌았습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 86 AND s.display_order = 3), '의무와 욕망 사이에서 갈등하다가 결국 마음이 이끄는 대로 결정했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 86 AND s.display_order = 3), '마음 깊은 곳에서 불안이 솟아올랐으나 겉으로는 태연한 척을 했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 86 AND s.display_order = 3), '기쁨과 슬픔이 동시에 밀려오는 복잡한 감정을 주체할 수가 없었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 86 AND s.display_order = 3), '양심의 가책이 잠들지 못하게 하여 결국 새벽에 진실을 고백했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 86 AND s.display_order = 3), '오랜 망설임 끝에 결심이 섰고 그 순간 마음이 한결 가벼워졌습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 86 AND s.display_order = 4), '침묵이 말보다 크게 울렸기에 차마 입을 열 수가 없었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 86 AND s.display_order = 4), '시간이 모래처럼 손가락 사이로 흘렀고 돌이킬 수 없는 법입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 86 AND s.display_order = 4), '희망이 어둠 속에서 작은 불꽃처럼 타올라 길을 밝혀 주었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 86 AND s.display_order = 4), '기억이 가을 낙엽처럼 하나씩 떨어지니 쓸쓸함만 남을 따름입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 86 AND s.display_order = 4), '그의 말이 상처처럼 가슴에 남아서 오랜 시간이 지나도 잊히지 않습니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 87 AND s.display_order = 1), '반복 실험을 통해 이 가설의 타당성이 입증되었으며 학계에서도 인정을 받았습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 87 AND s.display_order = 1), '광합성은 빛 에너지를 화학 에너지로 변환하는 과정이며 생태계의 기반입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 87 AND s.display_order = 1), '이 현상은 중력의 법칙으로 설명되지만 미시 세계에서는 예외가 존재합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 87 AND s.display_order = 1), '세포는 분열을 통해 증식하는데 이 과정에서 유전 정보가 복제됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 87 AND s.display_order = 1), '촉매는 반응 속도를 높이되 자체는 소모되지 않으므로 산업 활용도가 높습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 87 AND s.display_order = 2), '이 시스템은 데이터를 실시간으로 처리하여 정확한 의사 결정을 지원합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 87 AND s.display_order = 2), '알고리즘이 패턴을 자동 감지하고 이상 징후가 발견되면 즉시 알립니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 87 AND s.display_order = 2), '암호화가 데이터의 안전한 전송을 보장하므로 정보 유출 위험이 줄어듭니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 87 AND s.display_order = 2), '인공지능이 방대한 데이터를 분석하여 사람이 놓칠 수 있는 패턴을 찾습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 87 AND s.display_order = 2), '클라우드 컴퓨팅이 확장 가능한 인프라를 제공하기에 초기 투자가 절감됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 87 AND s.display_order = 3), '데이터가 두 변수 간의 강한 상관관계를 보여주며 인과성 검증이 필요합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 87 AND s.display_order = 3), '결과는 통계적으로 유의미하나 표본의 대표성에 대한 검토가 남아 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 87 AND s.display_order = 3), '표본 크기가 결과의 신뢰성에 영향을 미치므로 충분한 표본 확보가 필수입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 87 AND s.display_order = 3), '평균값이 지난 분기 대비 15% 증가했으며 이는 정책 효과로 분석됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 87 AND s.display_order = 3), '이상치를 제외하면 추세가 더 명확해지는바 데이터 정제가 선행되어야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 87 AND s.display_order = 4), '현재 추세에 기반하여 성장을 예측할 수 있으나 변수도 고려해야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 87 AND s.display_order = 4), '향후 10년간 수요가 두 배로 증가할 전망이므로 선제적 대응이 필요합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 87 AND s.display_order = 4), '이 기술은 산업 전반에 혁신을 가져올 것이며 고용 구조도 변화시킵니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 87 AND s.display_order = 4), '전문가들은 시장이 안정될 것으로 전망하나 불확실성은 여전히 남아 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 87 AND s.display_order = 4), '데이터에 따르면 이 추세는 지속될 가능성이 높고 가속화될 전망입니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 88 AND s.display_order = 1), '인플레이션이 10년래 최고치를 기록했으며 중앙은행의 개입이 불가피합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 88 AND s.display_order = 1), '실업률이 전월 대비 소폭 하락했으나 고용의 질적 개선은 미흡합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 88 AND s.display_order = 1), '국내총생산이 3분기 연속 성장했지만 수출 둔화가 우려 요인입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 88 AND s.display_order = 1), '소비자 신뢰 지수가 회복 조짐을 보이는바 내수 활성화가 기대됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 88 AND s.display_order = 1), '무역 적자가 사상 최대치에 달했으므로 구조적 개혁이 시급합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 88 AND s.display_order = 2), '주식시장이 급락 후 반등했으나 변동성이 커서 관망세가 이어지고 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 88 AND s.display_order = 2), '투자 포트폴리오를 다각화해야 하며 위험 분산이 장기 수익의 핵심입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 88 AND s.display_order = 2), '채권 수익률이 상승세를 보이고 있어서 안전 자산 선호가 강해집니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 88 AND s.display_order = 2), '시장 변동성이 투자자들의 불안을 키우고 있으므로 신중한 전략이 필요합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 88 AND s.display_order = 2), '장기 투자가 단기 투기보다 안정적이며 복리 효과로 수익이 극대화됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 88 AND s.display_order = 3), '거래가 500만 달러에 성사되었으며 양측이 만족하는 조건이었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 88 AND s.display_order = 3), '인수합병 계약이 최종 체결되었고 통합 절차가 곧 시작될 예정입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 88 AND s.display_order = 3), '양사가 전략적 제휴에 합의했으며 공동 연구 개발을 추진할 계획입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 88 AND s.display_order = 3), '계약 조건이 쌍방 검토를 거쳐 확정되었으니 서명 절차만 남았습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 88 AND s.display_order = 3), '이 거래는 주주 승인을 조건으로 하며 총회에서 최종 결정됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 88 AND s.display_order = 4), '연구개발 예산을 배정해야 하며 이는 미래 경쟁력의 원천이 됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 88 AND s.display_order = 4), '비용 절감 방안을 수립할 필요가 있으므로 각 부서별 분석을 시작합시다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 88 AND s.display_order = 4), '다음 분기 재무 전망을 검토하되 보수적 시나리오도 함께 준비합시다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 88 AND s.display_order = 4), '자본 지출이 예산을 초과하고 있어서 긴급 조정 회의가 필요합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 88 AND s.display_order = 4), '현금 흐름 관리가 기업 생존의 핵심이므로 월별 모니터링을 강화합시다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 89 AND s.display_order = 1), '피고는 사기 혐의로 유죄 판결을 받았으며 항소를 검토하고 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 89 AND s.display_order = 1), '원고는 손해배상을 청구할 권리가 있으나 입증 책임은 원고에게 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 89 AND s.display_order = 1), '법원은 항소를 기각하는 판결을 내렸고 원심이 그대로 확정되었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 89 AND s.display_order = 1), '증거가 불충분하여 무죄가 선고되었으므로 검찰이 재수사에 착수했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 89 AND s.display_order = 1), '판례에 따라 선례가 확립되었으며 이후 유사 사건에 적용될 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 89 AND s.display_order = 2), '본 서신을 통해 계약 해지를 통보하오니 관련 사항을 확인해 주십시오', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 89 AND s.display_order = 2), '규정 위반 사항을 공식적으로 알려드리며 소명 기회를 부여합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 89 AND s.display_order = 2), '이에 따라 시정 조치를 요구하오니 기한 내에 이행하여 주십시오', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 89 AND s.display_order = 2), '기한 내 이행하지 않을 경우 법적 조치를 취할 것임을 통보합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 89 AND s.display_order = 2), '관련 당사자에게 공식 통지가 발송되었으며 수령 확인을 요청합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 89 AND s.display_order = 3), '본 협정은 서명일로부터 발효되며 유효 기간은 5년으로 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 89 AND s.display_order = 3), '체약국은 본 조약의 조항을 준수해야 하며 위반 시 제재가 따릅니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 89 AND s.display_order = 3), '양국은 상호 이익을 위한 협력에 합의했고 구체적 이행 방안을 마련합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 89 AND s.display_order = 3), '분쟁은 국제 중재를 통해 해결되며 중재 판정은 최종적이고 구속력이 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 89 AND s.display_order = 3), '이 조약은 비준 절차를 거쳐 효력이 발생하며 양국 의회의 동의가 필요합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 89 AND s.display_order = 4), '회사는 간접 손해에 대해 책임을 지지 않으며 이는 계약서에 명시되어 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 89 AND s.display_order = 4), '불가항력으로 인한 지연은 면책되나 지체 없이 상대방에게 통지해야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 89 AND s.display_order = 4), '사용자는 자기 책임 하에 서비스를 이용하며 발생한 손해는 본인 부담입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 89 AND s.display_order = 4), '본 면책 조항은 관련 법률에 따라 해석되며 무효 조항은 분리 적용됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 89 AND s.display_order = 4), '최대 배상 한도는 계약 금액을 초과하지 않으며 이는 양측의 합의 사항입니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 90 AND s.display_order = 1), '로마에 가면 로마 법을 따르라고 하듯이 현지 문화를 존중해야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 90 AND s.display_order = 1), '백문이 불여일견이라 했으니 직접 가서 확인하는 것이 가장 정확합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 90 AND s.display_order = 1), '가는 말이 고와야 오는 말이 곱다고 하니 상대를 배려해서 말합시다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 90 AND s.display_order = 1), '호랑이도 제 말 하면 온다고 하니 사람 이야기는 조심하는 법입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 90 AND s.display_order = 1), '돌다리도 두드려 보고 건너라고 하듯이 신중한 확인이 필요합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 90 AND s.display_order = 2), '격식 표현과 비격식 표현은 상황에 따라 적절히 구분하여 사용해야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 90 AND s.display_order = 2), '유감을 전하는 표현도 격식에 따라 달라지므로 상황 파악이 중요합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 90 AND s.display_order = 2), '세대에 따라 같은 감정을 다르게 표현하기 마련이니 상호 이해가 필요합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 90 AND s.display_order = 2), '정중히 사양하는 표현과 가볍게 거절하는 표현은 격식에 따라 선택합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 90 AND s.display_order = 2), '감사를 전하는 방식이 격식과 비격식으로 나뉘며 관계에 따라 달라집니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 90 AND s.display_order = 3), '말장난은 의도한 게 아니었지만 분위기가 좋아져서 다행이었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 90 AND s.display_order = 3), '농담이니 진지하게 받아들이지 마시고 편하게 웃어 넘기세요', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 90 AND s.display_order = 3), '그의 유머 감각은 독특해서 처음에는 당혹스럽지만 곧 웃게 됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 90 AND s.display_order = 3), '웃지 않으면 울 수밖에 없으니 유머로 어려움을 극복하는 법입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 90 AND s.display_order = 3), '재치 있는 한마디가 분위기를 바꿨고 긴장된 협상이 풀리기 시작했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 90 AND s.display_order = 4), '같은 언어도 지역마다 표현이 다르므로 현지 표현을 익히면 도움이 됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 90 AND s.display_order = 4), '사투리는 그 지역의 문화를 반영하기에 언어 다양성의 중요한 자산입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 90 AND s.display_order = 4), '공식 언어와 구어체는 차이가 큰바 상황에 맞는 표현 선택이 중요합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 90 AND s.display_order = 4), '발음 차이로 같은 단어도 다르게 들리므로 지역별 특성을 이해해야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 90 AND s.display_order = 4), '지역 표현을 알면 현지인과 소통이 쉬워지며 문화적 유대감도 형성됩니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 91 AND s.display_order = 1), '자원이 부족한바 우선순위를 재조정하되 핵심 사업은 유지해야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 91 AND s.display_order = 1), '비용이 증가했을뿐더러 품질마저 저하되었으므로 전면 재검토가 불가피합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 91 AND s.display_order = 1), '경험이 부족하건대 선배의 조언을 구하되 최종 판단은 스스로 내려야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 91 AND s.display_order = 1), '수요가 급증한즉 공급 체계를 확충하거니와 품질 관리도 병행해야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 91 AND s.display_order = 1), '기한이 촉박할진대 효율을 극대화하되 정확성을 희생해서는 안 됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 91 AND s.display_order = 2), '같은 맥락에서 보건대 이 사례 역시 구조적 문제에서 비롯된 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 91 AND s.display_order = 2), '이 방식이 실패한 반면 대안적 접근은 성과를 거두었기에 전환이 시급합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 91 AND s.display_order = 2), '비용 절감에 기여할 뿐 아니라 효율성까지 높이므로 도입을 권고합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 91 AND s.display_order = 2), '경쟁사가 보수적 전략을 택한 데 반해 우리는 혁신을 추구하여 격차를 벌렸습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 91 AND s.display_order = 2), '다시 말해 기존 체계를 유지하면서도 새로운 방향을 모색해야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 91 AND s.display_order = 3), '이 점을 설명하자면 기술 발전이 고용 구조를 바꾼 사례를 들 수 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 91 AND s.display_order = 3), '대표적 사례로 재생 에너지가 전통 산업을 대체하면서 경제 구조가 변했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 91 AND s.display_order = 3), '구체적으로 말하면 세 가지 요인이 상호작용하여 이 현상을 초래했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 91 AND s.display_order = 3), '이 방법이 다양한 분야에 적용된바 그 효과가 실증적으로 입증되었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 91 AND s.display_order = 3), '즉 단기적 손실을 감수하고 장기 투자를 지속한 결과 성장 궤도에 진입했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 91 AND s.display_order = 4), '모든 증거를 종합하면 이 제안이 단기 부담에도 불구하고 장기적으로 최선입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 91 AND s.display_order = 4), '전반적으로 보면 긍정적 결과가 부정적 측면을 상쇄하고도 남으므로 추진합시다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 91 AND s.display_order = 4), '요약하자면 세 가지 핵심 사항이 상호 연관되어 있으며 통합적 접근이 필요합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 91 AND s.display_order = 4), '결국 지속가능성이 가장 중요한바 단기 성과에 집착하기보다 장기 전략을 세웁시다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 91 AND s.display_order = 4), '종합해 보면 이 프로젝트는 난관이 많았으나 기대 이상의 성과를 달성했습니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 92 AND s.display_order = 1), '그간의 업무량을 고려하건대 그가 극도로 지쳤을 것임이 틀림없습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 92 AND s.display_order = 1), '모든 정황을 종합하면 그것이 사실일 리가 없으므로 재조사가 필요합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 92 AND s.display_order = 1), '정보에 밝은 그녀이기에 그 소식을 이미 접했을 것이 분명합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 92 AND s.display_order = 1), '그의 경력과 전문성을 감안하면 그런 기초적 실수를 했을 리가 만무합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 92 AND s.display_order = 1), '핵심 관계자였던 그들이므로 사실관계를 파악하고 있었을 것이 당연합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 92 AND s.display_order = 2), '일정이 바빴던 점을 감안하면 그녀가 약속을 잊었을지도 모릅니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 92 AND s.display_order = 2), '대비가 없었더라면 상황이 훨씬 악화되었을 수도 있었기에 다행입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 92 AND s.display_order = 2), '소통이 부족했던 점을 고려하면 그가 취지를 오해했을 가능성이 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 92 AND s.display_order = 2), '그녀의 성향으로 미루어 볼 때 아마 다른 의견을 품고 있을 수도 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 92 AND s.display_order = 2), '회의 분위기가 좋지 않았으므로 그가 먼저 자리를 떠났을지도 모릅니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 92 AND s.display_order = 3), '출발 시각을 감안하건대 그는 지금쯤 도착해서 준비를 마쳤을 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 92 AND s.display_order = 3), '정보에 밝은 그녀이므로 우리보다 먼저 그 사실을 파악했을 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 92 AND s.display_order = 3), '그 시간대였으면 회의에 참석 중이었을 테니 연락이 안 되었을 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 92 AND s.display_order = 3), '마감일이 지났으므로 그 프로젝트는 이미 완료되어 검토 단계에 있을 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 92 AND s.display_order = 3), '정시 출발 원칙을 지키는 항공사이기에 비행기가 이미 이륙했을 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 92 AND s.display_order = 4), '준비가 부실했던 점을 감안하면 이 결과는 충분히 예견된 당연한 귀결입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 92 AND s.display_order = 4), '수집된 데이터를 분석한바 두 변수 간 인과관계가 존재한다고 추론됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 92 AND s.display_order = 4), '전제가 타당하고 논증 과정이 엄밀하므로 그 결론은 논리적으로 유효합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 92 AND s.display_order = 4), '이 증거들을 종합적으로 미루어 보건대 구조적 결함이 근본 원인입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 92 AND s.display_order = 4), '반복적 실험으로 동일한 결과가 나왔으므로 이 가설이 옳다고 판단됩니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 93 AND s.display_order = 1), '진실을 외면한 채 발전을 이룬 사회가 역사상 과연 존재했겠습니까?', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 93 AND s.display_order = 1), '자유와 평화를 동시에 원하지 않는 사람이 이 세상에 어디 있겠습니까?', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 93 AND s.display_order = 1), '이토록 조건이 완벽한 기회를 놓치고서 후회하지 않을 수 있겠습니까?', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 93 AND s.display_order = 1), '증거가 이처럼 명백한데도 여전히 의심의 여지가 남아 있겠습니까?', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 93 AND s.display_order = 1), '고통 없이 성장하고 시련 없이 성숙해진 사람이 과연 있었겠습니까?', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 93 AND s.display_order = 2), '처음에는 의심했고 다음에는 시도했으며 마침내 그 가치를 확신하게 되었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 93 AND s.display_order = 2), '배우고 성장했을 뿐 아니라 마침내 한계를 넘어 새로운 경지에 도달했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 93 AND s.display_order = 2), '좋은 정도가 아니라 훌륭했으며 나아가 역사에 남을 만한 성취였습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 93 AND s.display_order = 2), '걷기 시작하더니 뛰게 되었고 급기야 누구도 따라올 수 없는 속도에 이르렀습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 93 AND s.display_order = 2), '꿈을 꾸었고 계획을 세웠으며 실행에 옮긴 결과 마침내 현실이 되었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 93 AND s.display_order = 3), '노력 없이 얻은 것은 쉽게 사라지고 땀 흘려 얻은 것은 오래 남는 법입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 93 AND s.display_order = 3), '눈에서 멀어지면 마음에서도 멀어지듯 관심이 줄면 관계도 약해집니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 93 AND s.display_order = 3), '질문하지 않으면 답을 얻지 못하고 도전하지 않으면 성장할 수 없습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 93 AND s.display_order = 3), '실패를 두려워하면 도전할 수 없고 도전하지 않으면 성공도 불가능합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 93 AND s.display_order = 3), '말이 앞서면 신뢰가 무너지고 행동이 앞서면 존경이 쌓이는 법입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 93 AND s.display_order = 4), '버릴수록 더 많이 얻게 되고 비울수록 더 풍요로워지는 것이 삶의 역설입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 93 AND s.display_order = 4), '유일하게 변하지 않는 것은 변화 자체라는 사실이야말로 세상의 진리입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 93 AND s.display_order = 4), '알면 알수록 모르는 것이 더 많아진다는 깨달음이 진정한 지혜의 시작입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 93 AND s.display_order = 4), '가장 어두운 시기를 견뎌낸 자만이 가장 밝은 빛의 가치를 아는 법입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 93 AND s.display_order = 4), '진정한 강함이란 힘을 과시하는 것이 아니라 절제할 줄 아는 데서 나옵니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 94 AND s.display_order = 1), '본 논문은 기후 변화가 경제에 미치는 영향을 다각도로 검토하고자 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 94 AND s.display_order = 1), '이 연구의 목적은 기존 방법론의 한계를 극복할 새로운 분석 틀을 제안하는 데 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 94 AND s.display_order = 1), '이 주제에 대한 기존 연구가 제한적이므로 새로운 접근이 요구됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 94 AND s.display_order = 1), '본 연구는 선행 문헌의 공백을 메우거니와 실증적 근거를 추가로 제시하고자 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 94 AND s.display_order = 1), '이 분야에 대한 관심이 증가하고 있으나 체계적 분석은 부족하기에 본 연구가 필요합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 94 AND s.display_order = 2), '질적 연구와 양적 분석을 병행하여 결과의 신뢰도를 높이고자 하였습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 94 AND s.display_order = 2), '설문을 통해 수집된 데이터를 통계 분석한 후 심층 면접으로 보완하였습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 94 AND s.display_order = 2), '참가자를 무작위로 두 그룹에 배정한 후 변인을 통제하며 12주간 관찰했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 94 AND s.display_order = 2), '통계 분석으로 결과를 검증하되 질적 해석도 병행하여 타당성을 확보하였습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 94 AND s.display_order = 2), '12개월에 걸쳐 종단 연구를 수행하되 분기별로 중간 점검을 실시하였습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 94 AND s.display_order = 3), '연구 결과 두 집단 간 유의미한 차이가 관찰되었으며 이는 가설을 뒷받침합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 94 AND s.display_order = 3), '결과가 초기 가설을 뒷받침할 뿐 아니라 추가적인 함의까지 시사합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 94 AND s.display_order = 3), '두 변수 간 강한 상관관계가 발견되었으며 이는 선행 연구와 일치합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 94 AND s.display_order = 3), '데이터가 예상 패턴과 일치할 뿐 아니라 새로운 경향까지 드러내어 주목됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 94 AND s.display_order = 3), '실험군이 대조군보다 현저히 높은 성과를 보였으므로 개입의 효과가 입증되었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 94 AND s.display_order = 4), '이 주제에 대한 추가 연구가 필요한바 특히 장기적 효과에 대한 검증이 시급합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 94 AND s.display_order = 4), '표본 크기가 제한적이었던 점을 인정하며 향후 대규모 연구로 보완해야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 94 AND s.display_order = 4), '향후 연구에서는 보다 넓은 범위의 변수를 포함하되 문화적 맥락도 고려해야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 94 AND s.display_order = 4), '이 연구는 몇 가지 방법론적 한계가 있으나 그럼에도 유의미한 기여를 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 94 AND s.display_order = 4), '종단 연구를 통해 본 결과를 재확인하거니와 인과관계를 규명할 필요가 있습니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 95 AND s.display_order = 1), '이 정책은 불평등 해소를 목표로 하되 재정 건전성도 함께 확보하고자 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 95 AND s.display_order = 1), '시민의 적극적 참여가 민주주의의 근간인바 제도적 보장이 뒷받침되어야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 95 AND s.display_order = 1), '정부가 투명성을 높이겠다고 약속한 이상 실질적 이행 방안이 수반되어야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 95 AND s.display_order = 1), '사회적 합의 없이는 개혁이 어려운바 다양한 이해관계자의 참여가 전제됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 95 AND s.display_order = 1), '이 법안이 기본권 보호를 위해 제정되었으므로 실효성 있는 집행이 관건입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 95 AND s.display_order = 2), '찬성측은 경제적 이점을 강조하는 반면 사회적 비용은 간과하는 경향이 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 95 AND s.display_order = 2), '반대측이 환경 영향을 우려하는 것은 타당하나 대안 부재라는 한계도 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 95 AND s.display_order = 2), '이 문제에 대해 의견이 분분한바 객관적 데이터에 기반한 논의가 필요합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 95 AND s.display_order = 2), '양측 모두 타당한 논거를 제시하므로 일방적 판단보다 종합적 검토가 바람직합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 95 AND s.display_order = 2), '이 주제에 대해 공개 토론이 필요하되 감정보다 근거 중심으로 진행해야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 95 AND s.display_order = 3), '극단적 입장을 지양하고 균형 잡힌 접근을 취해야 합의에 도달할 수 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 95 AND s.display_order = 3), '양측 모두 일리가 있는바 각자의 주장에서 핵심만 추려 절충안을 마련합시다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 95 AND s.display_order = 3), '타협점을 찾는 것이 현명할뿐더러 장기적으로 모두에게 이익이 됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 95 AND s.display_order = 3), '의견이 다르더라도 공통된 기반을 찾아야 하며 그것이 건설적 대화의 출발점입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 95 AND s.display_order = 3), '서로의 입장을 존중하면서도 원칙은 지키되 유연하게 합의를 이끌어 냅시다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 95 AND s.display_order = 4), '지속가능한 발전이 필수적인바 단기 이익보다 장기 비전에 기반해 전략을 세워야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 95 AND s.display_order = 4), '미래 세대를 위해 지금 행동해야 하며 그 책임은 현세대 모두에게 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 95 AND s.display_order = 4), '장기적 관점에서 전략을 수립하되 변화하는 환경에 유연하게 대응해야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 95 AND s.display_order = 4), '기술 혁신이 문제의 열쇠가 될 것이나 윤리적 고려도 반드시 수반되어야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 95 AND s.display_order = 4), '교육 투자가 사회 발전의 기반인바 양적 확대와 질적 향상을 동시에 추구합시다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 96 AND s.display_order = 1), '얼마나 감사한지 말로 다할 수 없거니와 이 은혜를 평생 잊지 않겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 96 AND s.display_order = 1), '어려운 시기에 보여주신 친절을 잊지 않을 것이며 반드시 보답하겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 96 AND s.display_order = 1), '마음 깊이 감사드리며 이 인연이 오래도록 이어지기를 진심으로 바랍니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 96 AND s.display_order = 1), '함께했던 시간이 그리울 뿐 아니라 다시 만날 날을 손꼽아 기다립니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 96 AND s.display_order = 1), '진심으로 사과드리며 부족했던 점을 반성하고 신뢰를 회복하도록 노력하겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 96 AND s.display_order = 2), '기쁜 마음으로 축하를 전하며 앞으로의 여정에도 행복이 가득하시길 빕니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 96 AND s.display_order = 2), '무거운 마음으로 애도를 표하며 고인의 뜻이 길이 기억되기를 바랍니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 96 AND s.display_order = 2), '두 분의 앞날에 행복만 가득하길 바라며 서로를 향한 사랑이 변치 않길 빕니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 96 AND s.display_order = 2), '고인의 명복을 빌며 유족께서 슬픔을 이겨내실 수 있도록 진심으로 위로드립니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 96 AND s.display_order = 2), '이 뜻깊은 자리를 함께하게 되어 영광이며 오래도록 기억에 남을 순간입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 96 AND s.display_order = 3), '천 리 길도 한 걸음부터 시작되듯 작은 실천이 큰 변화를 만드는 법입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 96 AND s.display_order = 3), '실패가 성공의 밑거름이 되는 법이니 좌절하지 말고 교훈으로 삼으십시오', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 96 AND s.display_order = 3), '포기하지 않는 한 실패란 없으며 매 시도가 성공을 향한 한 걸음입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 96 AND s.display_order = 3), '한계란 스스로 만드는 것이기에 상상력을 확장하면 가능성도 함께 커집니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 96 AND s.display_order = 3), '오늘 심은 작은 씨앗이 내일의 숲이 되듯 꾸준한 노력은 반드시 결실을 맺습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 96 AND s.display_order = 4), '돌이켜보면 그 힘든 경험이 저를 성장시켰거니와 지금의 저를 만든 원동력입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 96 AND s.display_order = 4), '그때는 몰랐으나 시간이 흐른 지금에야 그 의미를 비로소 깨닫게 되었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 96 AND s.display_order = 4), '과거의 실수로부터 배운 교훈을 바탕으로 더 나은 미래를 설계할 수 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 96 AND s.display_order = 4), '그 시련을 겪지 않았더라면 지금의 성숙한 내가 존재할 수 없었을 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 96 AND s.display_order = 4), '시간이 흐른 뒤에야 비로소 그 가치를 알게 된바 감사함을 뒤늦게 느낍니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 97 AND s.display_order = 1), '일부 문화에서는 직접적 거절이 무례하게 여겨지므로 우회적 표현을 익혀야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 97 AND s.display_order = 1), '문화적 맥락을 이해하는 것이 중요한바 표면적 행동만으로 판단해서는 안 됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 97 AND s.display_order = 1), '제스처의 의미가 나라마다 다를 수 있으므로 사전에 확인하는 것이 현명합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 97 AND s.display_order = 1), '상대의 문화적 배경을 존중해야 하거니와 자국 문화를 기준으로 판단해서는 안 됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 97 AND s.display_order = 1), '문화적 오해는 의도치 않게 발생할 수 있으므로 열린 자세로 소통하는 것이 중요합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 97 AND s.display_order = 2), '다양성이 시야를 넓혀줄 뿐 아니라 혁신의 원천이 되기에 적극 추구해야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 97 AND s.display_order = 2), '서로 다른 관점이 모일 때 더 나은 해결책이 나오므로 다양성은 곧 강점입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 97 AND s.display_order = 2), '다양한 배경의 구성원이 팀의 강점이 되려면 포용적 환경이 전제되어야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 97 AND s.display_order = 2), '포용적 환경이 창의성을 촉진하며 나아가 조직의 경쟁력을 높이는 핵심입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 97 AND s.display_order = 2), '차이를 인정하는 것이 조화의 시작이며 존중을 바탕으로 한 협력이 성장의 열쇠입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 97 AND s.display_order = 3), '많은 나라에서 악수가 관례이나 접촉을 꺼리는 문화도 있으므로 주의가 필요합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 97 AND s.display_order = 3), '명함을 양손으로 주고받는 것이 예의인바 받은 즉시 확인하는 것도 중요합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 97 AND s.display_order = 3), '식사 예절이 나라마다 크게 다르므로 사전에 현지 관행을 파악해야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 97 AND s.display_order = 3), '시간 약속에 대한 인식이 문화마다 다르기에 상대 기준에 맞추는 것이 바람직합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 97 AND s.display_order = 3), '선물을 줄 때 문화적 금기를 확인해야 하며 의도치 않은 결례를 방지해야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 97 AND s.display_order = 4), '모든 사람이 동등한 기회를 누려야 하며 이를 위한 제도적 장치가 필요합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 97 AND s.display_order = 4), '배경에 관계없이 모든 목소리가 중요하므로 소수 의견도 경청하는 문화가 필요합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 97 AND s.display_order = 4), '공정한 대우는 기본적 권리인바 이를 실현하기 위한 구체적 노력이 필요합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 97 AND s.display_order = 4), '언어가 포용성을 반영해야 하기에 무의식적 편견이 담긴 표현은 지양합시다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 97 AND s.display_order = 4), '다름이 차별의 이유가 될 수 없으며 오히려 사회를 풍요롭게 하는 자원입니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 98 AND s.display_order = 1), '오늘 이 뜻깊은 자리에 서게 되어 영광이며 의미 있는 논의가 되길 바랍니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 98 AND s.display_order = 1), '귀한 시간을 내주신 여러분께 감사드리며 핵심 주제로 바로 들어가겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 98 AND s.display_order = 1), '오늘 다룰 주제는 우리 모두에게 중대한 영향을 미치는 사안이기에 주목해 주십시오', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 98 AND s.display_order = 1), '먼저 한 가지 질문으로 시작하겠으며 이것이 오늘 논의의 방향을 제시할 것입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 98 AND s.display_order = 1), '초대해 주셔서 감사하며 이 자리가 상호 이해를 깊게 하는 계기가 되길 바랍니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 98 AND s.display_order = 2), '오늘 전하고 싶은 핵심은 협력 없이는 어떤 혁신도 지속될 수 없다는 점입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 98 AND s.display_order = 2), '가장 중요한 점을 강조하건대 실행력 없는 계획은 공허한 구호에 불과합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 98 AND s.display_order = 2), '이것이 왜 중요한지 세 가지 이유를 말씀드리겠으니 주의 깊게 들어 주십시오', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 98 AND s.display_order = 2), '핵심은 개인의 역량이 아니라 협력의 시너지이며 이것이 조직의 미래를 결정합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 98 AND s.display_order = 2), '오늘 한 가지만 기억하신다면 변화는 실천에서 시작된다는 점을 명심하십시오', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 98 AND s.display_order = 3), '한 가지 여쭤보겠는데 이런 경험이 있으신 분은 손을 들어 주시겠습니까?', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 98 AND s.display_order = 3), '이 의견에 동의하시는 분은 손을 들어 주시면 논의의 방향을 정하겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 98 AND s.display_order = 3), '잠시 옆 분과 이 주제에 대해 의견을 나눈 후 함께 공유해 봅시다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 98 AND s.display_order = 3), '여러분이라면 이 상황에서 어떤 선택을 하시겠습니까? 솔직한 의견을 듣고 싶습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 98 AND s.display_order = 3), '이 딜레마에서 어떻게 판단하시겠습니까? 다양한 관점을 환영합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 98 AND s.display_order = 4), '마무리하면서 한 가지 당부드리건대 오늘의 논의를 실천으로 이어 주십시오', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 98 AND s.display_order = 4), '끝까지 경청해 주셔서 진심으로 감사드리며 뜻깊은 대화가 되었길 바랍니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 98 AND s.display_order = 4), '오늘 말씀드린 내용이 영감이 되어 각자의 자리에서 변화를 이끌어 주십시오', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 98 AND s.display_order = 4), '함께 더 나은 미래를 만들어 갑시다, 그 시작은 바로 오늘 이 자리에서입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 98 AND s.display_order = 4), '질문이 있으시면 기꺼이 답변드리겠으며 추가 논의도 환영합니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 99 AND s.display_order = 1), '장벽 없는 세상을 상상해 보되 그것을 현실로 만들려면 무엇이 필요한지 생각합시다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 99 AND s.display_order = 1), '평범했던 어느 날 모든 것이 달라지기 시작했으며 그 순간이 전환점이 되었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 99 AND s.display_order = 1), '이런 상황을 그려보되 만약 다른 선택을 했다면 결과가 어떠했을지 생각해 봅시다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 99 AND s.display_order = 1), '사소해 보였던 하나의 결정이 연쇄 반응을 일으켜 결국 모든 것을 바꿨습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 99 AND s.display_order = 1), '아무도 예상하지 못한 일이 일어났으며 그로 인해 모두의 인식이 바뀌었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 99 AND s.display_order = 2), '이 결정의 영향을 깊이 고려해야 하며 단기적 편의보다 장기적 결과를 우선시합시다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 99 AND s.display_order = 2), '증거가 압도적으로 이 사실을 뒷받침하기에 이를 부정하는 것은 비합리적입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 99 AND s.display_order = 2), '지금 행동하지 않으면 기회를 영영 잃게 되므로 신속한 결단이 요구됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 99 AND s.display_order = 2), '통계가 분명히 보여주는 바를 무시할 수 없으며 객관적 근거에 따라 판단합시다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 99 AND s.display_order = 2), '이것이 올바른 선택인 이유를 논증하겠으며 반론에 대해서도 명확히 답하겠습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 99 AND s.display_order = 3), '이 작품은 시대의 본질을 포착했을 뿐 아니라 새로운 관점까지 제시합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 99 AND s.display_order = 3), '자세히 살펴보면 숨겨진 의미가 드러나며 표면적 해석과는 전혀 다른 결론에 이릅니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 99 AND s.display_order = 3), '이 접근 방식은 장점과 단점이 공존하므로 맥락에 따라 적용을 달리해야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 99 AND s.display_order = 3), '표면 아래 더 깊은 메시지가 있으며 그것을 포착하려면 다층적 분석이 필요합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 99 AND s.display_order = 3), '이 현상을 다각도로 분석해야 하거니와 단일 시각으로는 본질을 파악할 수 없습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 99 AND s.display_order = 4), '새벽이 하늘을 물들이자 어둠 속에 잠들었던 세상이 비로소 숨을 쉬기 시작했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 99 AND s.display_order = 4), '침묵이 천 마디 말보다 깊은 울림을 전했으며 그 여운은 오래도록 가시지 않았습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 99 AND s.display_order = 4), '바람이 나뭇잎 사이로 속삭이자 잊혀진 기억들이 하나둘 되살아나기 시작했습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 99 AND s.display_order = 4), '시간이 멈춘 듯한 그 순간 세상의 소음은 사라지고 오직 고요만이 남았습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 99 AND s.display_order = 4), '별빛 아래 도시가 보석처럼 반짝이는 동안 누군가의 꿈이 조용히 피어나고 있었습니다', '기본');
INSERT INTO sentences (skill_id, meaning, sentence_type) VALUES
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 100 AND s.display_order = 1), '옛말에 시간은 금이라 했듯이 한번 흘러간 시간은 어떤 대가로도 되돌릴 수 없습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 100 AND s.display_order = 1), '행동이 말보다 크다고 하듯 실천 없는 약속은 신뢰를 오히려 무너뜨립니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 100 AND s.display_order = 1), '서두르면 일을 그르친다는 속담처럼 조급한 판단은 더 큰 손실을 초래합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 100 AND s.display_order = 1), '아는 것이 힘이라는 말이 있듯 지식의 격차가 곧 기회의 격차로 이어집니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 100 AND s.display_order = 1), '예방이 치료보다 낫다는 교훈처럼 사전 대비가 사후 수습보다 효과적입니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 100 AND s.display_order = 2), '두 단어 사이에 미묘한 차이가 있으므로 맥락에 따라 구분하여 사용해야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 100 AND s.display_order = 2), '같은 말이라도 어조에 따라 의미가 달라지기에 비언어적 요소도 고려해야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 100 AND s.display_order = 2), '이 표현은 격식체에서만 적절한바 일상 대화에서 쓰면 어색하게 들립니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 100 AND s.display_order = 2), '직역하면 의미가 완전히 달라지므로 문화적 맥락을 반영한 의역이 필요합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 100 AND s.display_order = 2), '문맥에 따라 해석이 크게 달라질 수 있으므로 전후 상황을 반드시 파악합시다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 100 AND s.display_order = 3), '이보다 더 잘 표현할 수 없을 만큼 그 순간의 감동은 압도적이었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 100 AND s.display_order = 3), '이 경험이 제 인생을 바꿔놓았을 뿐 아니라 세상을 보는 눈까지 달라졌습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 100 AND s.display_order = 3), '말로는 다 할 수 없는 감동이었으며 그 여운이 지금까지도 깊이 남아 있습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 100 AND s.display_order = 3), '그 순간의 감정을 어떤 말로도 담을 수 없기에 침묵이 가장 진실한 표현이었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 100 AND s.display_order = 3), '이 만남은 제게 큰 의미가 있거니와 앞으로의 방향을 결정짓는 전환점이 되었습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 100 AND s.display_order = 4), '위 모든 사항을 고려하면 결론이 분명해지며 더 이상 미룰 이유가 없습니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 100 AND s.display_order = 4), '복잡한 문제일수록 단순한 해결책이 필요하되 본질을 놓쳐서는 안 됩니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 100 AND s.display_order = 4), '과거의 교훈을 바탕으로 미래를 설계하되 변화하는 환경에 유연하게 대응합시다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 100 AND s.display_order = 4), '진정한 소통은 듣는 것에서 시작되며 상대를 이해하려는 노력이 수반되어야 합니다', '기본'),
  ((SELECT s.id FROM skills s JOIN levels l ON s.level_id = l.id WHERE l.level_number = 100 AND s.display_order = 4), '끊임없는 배움만이 성장의 유일한 길이기에 겸손한 자세로 끝없이 정진합시다', '기본');
